#define BUFFER_SIZE 100

typedef struct {
    uint16_t buffer[BUFFER_SIZE];
    size_t head;
    size_t tail;
} CircularBuffer;

void init_circular_buffer(CircularBuffer *cb) {
    cb->head = 0;
    cb->tail = 0;
}

int is_full(CircularBuffer *cb) {
    return (cb->head == (cb->tail + 1) % BUFFER_SIZE);
}

int is_empty(CircularBuffer *cb) {
    return (cb->head == cb->tail);
}

int add_to_circular_buffer(CircularBuffer *cb, uint16_t value) {
    if (is_full(cb)) {
        return -1; // Buffer full
    }
    cb->buffer[cb->head] = value;
    cb->head = (cb->head + 1) % BUFFER_SIZE;
    return 0;
}

uint16_t get_from_circular_buffer(CircularBuffer *cb) {
    if (is_empty(cb)) {
        return -1; // Buffer empty
    }
    uint16_t value = cb->buffer[cb->tail];
    cb->tail = (cb->tail + 1) % BUFFER_SIZE;
