int calculate_fan_speed(float temperature);
void set_fan_speed(int speed);
void log_data(float temperature, int fan_speed);
void cleanup_handler(int signal);

// Signal handler for graceful shutdown
void cleanup_handler(int signal) {
    printf("\nCaught signal %d, cleaning up...\n", signal);
    running = false;
    if (log_file != NULL) {
        fclose(log_file);
    }
    wiringPiSPIDataRW(SPI_CHANNEL, NULL, 0); // Reset SPI
    pinMode(FAN_GPIO, INPUT); // Set GPIO back to input
    exit(0);
}

// Reads temperature data from MAX31855 thermocouple via SPI
float read_temperature() {
    unsigned char buffer[4];
    int raw_temp;
    float temperature;

    // Read data from SPI
    if (wiringPiSPIDataRW(SPI_CHANNEL, buffer, 4) == -1) {
        fprintf(stderr, "Error reading SPI data: %s\n", strerror(errno));
        return -273.15; // Return absolute zero as error indicator
    }

    // Check for fault bits
    if (buffer[3] & 0x01) {
        fprintf(stderr, "Thermocouple fault: Open circuit\n");
        return -273.15;
    } else if (buffer[3] & 0x02) {
        fprintf(stderr, "Thermocouple fault: Short to VCC\n");
        return -273.15;
    } else if (buffer[3] & 0x04) {
        fprintf(stderr, "Thermocouple fault: Short to GND\n");
        return -273.15;
    } else if (buffer[3] & 0x08) {
        fprintf(stderr, "Thermocouple fault: Shunt voltage fault\n");
        return -273.15;
    }

    // Extract raw temperature data (bits 18-31)
    raw_temp = ((buffer[0] << 8) | buffer[1]) >> 2;

    // Convert to Celsius
    temperature = raw_temp * 0.25;

    return temperature;
}

