int calculate_fan_speed(float temperature) {
    int speed;

    if (temperature < TEMP_THRESHOLD_LOW) {
        speed = 0;
    } else if (temperature > TEMP_THRESHOLD_HIGH) {
        speed = 100;
    } else {
        speed = (int)(((temperature - TEMP_THRESHOLD_LOW) / (TEMP_THRESHOLD_HIGH - TEMP_THRESHOLD_LOW)) * 100.0);
    }

    return speed;
}

