#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Constants
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1 MHz
#define ADC_CHANNEL 0
#define ALARM_LED_PIN 1   // wiringPi pin 1 (GPIO 18)
#define AIRFLOW_THRESHOLD 1.0 // Volts
#define ADC_MAX_VALUE 1023
#define ADC_REF_VOLTAGE 3.3 // Volts

// Global variables
FILE *logFile = NULL;
volatile sig_atomic_t programRunning = 1;

// Function prototypes
int setup();
int readSensor();
float calculateVoltage(int adcValue);
void logData(float voltage);
void triggerAlarm();
void signalHandler(int signal);
void cleanup();

/**
 * @brief Signal handler for graceful shutdown.
 * @param signal The signal received.
 */
void signalHandler(int signal) {
  programRunning = 0;
  printf("Caught signal %d, exiting gracefully.\n", signal);
  cleanup();
  exit(0);
}

/**
 * @brief Sets up the wiringPi library and SPI communication.
 * @return 0 on success, -1 on failure.
 */
int setup() {
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "wiringPiSetup failed\n");
    return -1;
  }

  if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
    fprintf(stderr, "wiringPiSPISetup failed\n");
    return -1;
  }

  pinMode(ALARM_LED_PIN, OUTPUT);
  digitalWrite(ALARM_LED_PIN, LOW); // Ensure LED is off initially

  logFile = fopen("airflow_log.txt", "a");
  if (logFile == NULL) {
    perror("Error opening log file");
    return -1;
  }

  return 0;
}

/**
 * @brief Reads the sensor value from the MCP3008 ADC.
 * @return The ADC reading (0-1023), or -1 on failure.
 */
int readSensor() {
  unsigned char buffer[3];
  int adcValue;

  buffer[0] = 0x01; // Start bit
  buffer[1] = (0x08 | ADC_CHANNEL) << 4; // Single-ended mode, ADC channel selection
  buffer[2] = 0x00; // Don't care

  wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);

  adcValue = ((buffer[1] & 0x03) << 8) + buffer[2];

  return adcValue;
}

/**
 * @brief Calculates the voltage from the ADC reading.
 * @param adcValue The ADC reading (0-1023).
 * @return The voltage (0-3.3V).
 */
float calculateVoltage(int adcValue) {
  return ((float)adcValue / ADC_MAX_VALUE) * ADC_REF_VOLTAGE;
}

/**
 * @brief Logs the voltage data to the log file with a timestamp.
 * @param voltage The voltage value to log.
 */
void logData(float voltage) {
  time_t rawtime;
  struct tm *timeinfo;
  char timestamp[80];

  time(&rawtime);
  timeinfo = localtime(&rawtime);

  strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

  fprintf(logFile, "%s, %.3fV\n", timestamp, voltage);
  fflush(logFile); // Ensure data is written to disk immediately
}

/**
 * @brief Triggers the alarm by setting the LED HIGH for 2 seconds, then LOW.
 */
void triggerAlarm() {
  digitalWrite(ALARM_LED_PIN, HIGH);
  delay(2000);
  digitalWrite(ALARM_LED_PIN, LOW);
}

/**
 * @brief Cleans up resources before exiting.
 */
void cleanup() {
  if (logFile != NULL) {
    fclose(logFile);
  }
  digitalWrite(ALARM_LED_PIN, LOW);
}

int main() {
  // Register signal handler for Ctrl+C
  signal(SIGINT, signalHandler);

  if (setup() == -1) {
    return 1;
  }

  printf("Airflow monitoring started. Press Ctrl+C to exit.\n");

  while (programRunning) {
    int adcValue = readSensor();
    if (adcValue == -1) {
      fprintf(stderr, "Failed to read sensor data\n");
      delay(500); // Wait before retrying
      continue;
    }

    float voltage = calculateVoltage(adcValue);
    logData(voltage);

    if (voltage < AIRFLOW_THRESHOLD) {
      printf("Airflow below threshold! Triggering alarm.\n");
      triggerAlarm();
    }

    delay(500);
  }

  return 0;
}

