To create a C program for the Raspberry Pi 3 Model B+ to interface with a Honeywell AWM5300V airflow sensor, we need to follow these steps:

1. Set up the wiringPi library.
2. Read the analog voltage from the sensor.
3. Convert the analog voltage to a digital value.
4. Log the readings along with the timestamp in a file named `airflow_log.txt`.
5. Trigger an alarm via GPIO if the airflow drops below a certain threshold.

First, ensure you have the wiringPi library installed on your Raspberry Pi. If not, you can install it using the following commands:

```sh
git clone http://wiringpi.com/wiringpi.git
cd wiringpi
./build
```

Now, let's write the C program:

```c
#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>
#include <time.h>

#define SENSOR_PIN 0  // Analog pin connected to the sensor
#define LOG_FILE "airflow_log.txt"
#define THRESHOLD_VOLTAGE 0.7  // Threshold voltage in volts

void log_data(double voltage, time_t timestamp) {
    FILE *file;
    file = fopen(LOG_FILE, "a");
    if (file == NULL) {
        perror("Error opening file");
        exit(EXIT_FAILURE);
    }
    fprintf(file, "%s, %.4f\n", ctime(&timestamp), voltage);
    fclose(file);
}

int main() {
    int fd, i, adc_value;
    double voltage;

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        printf("Failed to initialize wiringPi.\n");
        return 1;
    }

    // Open the ADC device
    fd = wiringPiI2CSetup(0x48);  // Assuming the ADC is connected to address 0x48

    if (fd < 0) {
        printf("Failed to open ADC device.\n");
        return 1;
    }

    while (1) {
        // Read from the ADC
        adc_value = wiringPiI2CReadReg8(fd, 0x00);

        // Convert ADC value to voltage
        voltage = (double)adc_value * (5.0 / 1023.0);

        // Log the data
        log_data(voltage, time(NULL));

        // Check if the voltage is below the threshold
        if (voltage < THRESHOLD_VOLTAGE) {
            printf("Warning: Airflow below threshold (%.4f V)\n", voltage);
            // Trigger an alarm via GPIO
            pinMode(18, OUTPUT);  // Use GPIO 18 as an example
            digitalWrite(18, HIGH);
            delay(1000);  // Stay high for 1 second
            digitalWrite(18, LOW);
        }

        // Sleep for a short period before the next reading
        delay(1000);
    }

    return 0;
}
```

