```

Now, here is the C program:

```c
#include <wiringPi.h>
#include <stdio.h>

#define BUTTON_PIN 0   // BCM GPIO 17 is pin 0 in WiringPi
#define LED_PIN    1   // For demonstration, let's use pin 1 for another LED

int main(void)
{
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        printf("wiringPiSetup failed!\n");
        return 1;
    }

    // Set up the button pin as input with internal pull-up resistor
    pinMode(BUTTON_PIN, INPUT);
    pullUpDnControl(BUTTON_PIN, PUD_UP);

    // Set up the LED pin as output
    pinMode(LED_PIN, OUTPUT);

    int buttonState = HIGH;  // Initial state of the button
    while (1) {
        // Read the current state of the button
        int currentState = digitalRead(BUTTON_PIN);

        // Check if the button state has changed
        if (currentState != buttonState) {
            // Debounce the button by checking over a short period
            delay(50);
            currentState = digitalRead(BUTTON_PIN);

            if (currentState != buttonState) {
                // Button state has settled
                if (currentState == LOW) {
                    // Button was pressed
                    digitalWrite(LED_PIN, HIGH);  // Turn on the LED
                } else {
                    // Button was released
                    digitalWrite(LED_PIN, LOW);   // Turn off the LED
                }
            }
        }

        buttonState = currentState;
    }

    return 0;
}
```

