// Function to read temperature from LM75 sensor
float read_temperature(int i2c_handle) {
    int reading;
    if (i2c_handle < 0) return -273.15; // Return absolute zero if handle is invalid

    reading = i2cReadByteData(i2c_handle, 0); // LM75 temperature register
    if (reading < 0) {
        fprintf(stderr, "Error reading temperature: %d\n", reading);
        return -273.15; // Return absolute zero on I2C error
    }

    float temp_c = (float)((int8_t)reading) + (float)(i2cReadByteData(i2c_handle, 1) >> 7) * 0.5;

    // Validate temperature range
    if (temp_c < -55.0 || temp_c > 125.0) {
        fprintf(stderr, "Invalid temperature reading: %.2f\n", temp_c);
        return -273.15; // Return absolute zero if out of range
    }

    return temp_c;
}

// Function to control fan speed based on temperature
void control_fan(float temperature) {
    int duty_cycle;

    if (temperature <= 20.0) {
        duty_cycle = 0;
    } else if (temperature >= 60.0) {
        duty_cycle = 1000000; // Max duty cycle
    } else {
        duty_cycle = (int)((temperature - 20.0) / (60.0 - 20.0) * 1000000.0);
    }

    gpioPWM(FAN_GPIO, duty_cycle);
}

