#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <wiringPi.h>
#include <wiringPiI2C.h>

#define LM75_ADDRESS 0x90 // LM75 default address
#define FAN_PIN 18        // PWM fan connected to GPIO18

// Function to initialize I2C
int init_i2c() {
    int fd = -1;
    if (wiringPiI2CSetup(LM75_ADDRESS) < 0) {
        perror("Failed to initialize I2C");
        exit(EXIT_FAILURE);
    }
    return fd;
}

