    unsigned char temp[2];
    int16_t rawTemp;
    float tempC;

    if (read(fd, &temp, 2) != 2) {
        perror("Failed to read temperature");
        return -1.0;
    }

    rawTemp = (temp[0] << 8) | temp[1];
    tempC = (rawTemp / 16.0);

    return tempC;
}

// Function to control the PWM fan
void control_fan(int fd, float tempC) {
    int fan_speed = 0;

    // Simple logic: Increase fan speed as temperature increases
    if (tempC > 30.0) {
        fan_speed = 255; // Full speed
    } else if (tempC > 25.0) {
        fan_speed = 200; // High speed
    } else if (tempC > 20.0) {
        fan_speed = 150; // Medium speed
    } else {
        fan_speed = 50; // Low speed
    }

    wiringPiPCA9685Setup(FAN_PIN, 4096, 0x40); // 200Hz frequency
    wiringPiPCA9685SetPWMFreq(4096);
    wiringPiPCA9685SetPWM(FAN_PIN, 0, fan_speed);
}

// Function to log temperature and fan speed
