    FILE *file;
    time_t now;
    struct tm *timeinfo;

    time(&now);
    timeinfo = localtime(&now);

    file = fopen("cooling_log.txt", "a");
    if (!file) {
        perror("Failed to open file for logging");
        exit(EXIT_FAILURE);
    }

    fprintf(file, "%s - Temperature: %.2f°C, Fan Speed: %d\n", asctime(timeinfo), tempC, fan_speed);
    fclose(file);
}

int main() {
    int fd = -1;
    float tempC;

    if (wiringPiSetup() == -1) {
        perror("wiringPi setup failed");
        exit(EXIT_FAILURE);
    }

    fd = init_i2c();
    if (fd == -1) {
        exit(EXIT_FAILURE);
    }

    while (1) {
        tempC = read_temperature(fd);
        if (tempC >= 0.0) {
            control_fan(fd, tempC);
            log_data(tempC, 255); // Assuming full speed for fan speed logging
        } else {
            log_data(-1.0, 0); // Log error in logging
        }

        sleep(1); // Wait for 1 second before next reading
    }

    close(fd);
    return 0;
}
