To achieve this, you will need to use the `pigpio` library, which provides GPIO access on the Raspberry Pi. The SSD1306 is a popular OLED display driver that can be controlled via I2C or SPI. For simplicity, we'll use I2C to interface with the SSD1306.

First, ensure you have the `pigpio` library installed. You can install it using:

```sh
sudo apt-get update
sudo apt-get install pigpio
```

Next, you will need to include the necessary headers and set up the I2C communication with the SSD1306. Here is a complete example of how to write a C program to initialize an SSD1306 OLED display and display the current time in HH:MM:SS format, updating every second.

### Step 1: Initialize the SSD1306 Display

The SSD1306 display has a default I2C address of `0x3C`. You will need to initialize the display and configure it.

### Step 2: Display Time

We will use the `time.h` library to get the current time and convert it into the desired format.

Here is the complete C program:

```c
#include <pigpio.h>
#include <stdio.h>
#include <string.h>
#include <time.h>

#define SSD1306_I2C_ADDRESS 0x3C
#define SSD1306_WIDTH 128
#define SSD1306_HEIGHT 64

// SSD1306 commands
#define SSD1306_CMD_DISPLAYOFF 0xAE
#define SSD1306_CMD_SETDISPLAYCLOCKDIV 0xD5
#define SSD1306_CMD_SETMULTIPLEXRATIO 0xA8
#define SSD1306_CMD_SETDISPLAYOFFSET 0xD3
#define SSD1306_CMD_SETSTARTLINE 0x40
#define SSD1306_CMD_CHARGEPUMP 0x8D
#define SSD1306_CMD_MEMORYMODE 0x20
#define SSD1306_CMD_SETCOLUMN 0x15
#define SSD1306_CMD_SETROW 0x75
#define SSD1306_CMD_PRECHARGE 0xd9
#define SSD1306_CMD_VCOMH 0xdb
#define SSD1306_CMD_NORMALDISPLAY 0xA6
#define SSD1306_CMD_INVERTDISPLAY 0xA7
#define SSD1306_CMD_DISPLAYALLON_RESUME 0xA4
#define SSD1306_CMD_DISPLAYNORMAL_RESUME 0xA5
#define SSD1306_CMD_SETCONTRAST 0x81
#define SSD1306_CMD_DEACTIVATE_SCROLL 0x2E
#define SSD1306_CMD_ACTIVATE_SCROLL 0x2F
#define SSD1306_CMD_SET_VERTICAL_SCROLL_AREA 0xA3
#define SSD1306_CMD_SCROLL_DEACTIVATE 0x2E
#define SSD1306_CMD_SCROLL_ACTIVATE 0x2F
#define SSD1306_CMD_RIGHT_HORIZONTAL_SCROLL 0x26
#define SSD1306_CMD_LEFT_HORIZONTAL_SCROLL 0x27
#define SSD1306_CMD_VERTICAL_AND_RIGHT_HORIZONTAL_SCROLL 0x29
#define SSD1306_CMD_VERTICAL_AND_LEFT_HORIZONTAL_SCROLL 0x2A
#define SSD1306_CMD_DISPLAYON 0xAF

int init_display(int i2c_address) {
    int fd = gpioInitialise();
    if (fd < 0) {
        printf("Failed to initialize pigpio\n");
        return -1;
    }

    // Set the I2C address
    gpioI2CSetAddress(fd, i2c_address);

    // Display off
    gpioI2CWriteReg16(fd, 0x00, SSD1306_CMD_DISPLAYOFF);

    // Set display clock divide ratio/oscillator frequency
    gpioI2CWriteReg16(fd, 0x80, SSD1306_CMD_SETDISPLAYCLOCKDIV);
    gpioI2CWriteReg16(fd, 0xF0, 0x80); // RATIO = D/C PCLK / OscFreq = 1/15

    // Set multipler
    gpioI2CWriteReg16(fd, 0x80, SSD1306_CMD_SETMULTIPLEXRATIO);
    gpioI2CWriteReg16(fd, 0x1F, 0x80); // 128

    // Set display offset
    gpioI2CWriteReg16(fd, 0x80, SSD1306_CMD_SETDISPLAYOFFSET);
    gpioI2CWriteReg16(fd, 0x00, 0x80); // 0

    // Set start line address
    gpioI2CWriteReg16(fd, 0x80, SSD1306_CMD_SETSTARTLINE);
    gpioI2CWriteReg16(fd, 0x00, 0x80); // line 0

    // Charge pump
    gpioI2CWriteReg16(fd, 0x80, SSD1306_CMD_CHARGEPUMP);
    gpioI2CWriteReg16(fd, 0x14, 0x80); // 1

    // Set memory addressing mode
    gpioI2CWriteReg16(fd, 0x00, SSD1306_CMD_MEMORYMODE);
    gpioI2CWriteReg16(fd, 0x00, 0x00); // 0x00 = horizontal addressing mode

    // Column address
    gpioI2CWriteReg16(fd, 0x10, SSD1306_CMD_SETCOLUMN);
    gpioI2CWriteReg16(fd, 0x00, 0x00); // Start column
    gpioI2CWriteReg16(fd, 0x7F, 0x00); // End column

    // Page address
    gpioI2CWriteReg16(fd, 0x11, SSD1306_CMD_SETROW);
    gpioI2CWriteReg16(fd, 0x00, 0x00); // Start row
    gpioI2CWriteReg16(fd, 0x07, 0x00); // End row

    // Set contrast
    gpioI2CWriteReg16(fd, 0x81, SSD1306_CMD_SETCONTRAST);
    gpioI2CWriteReg16(fd, 0x7F, 0x81); // Contrast setting

    // Set pre-charge period
    gpioI2CWriteReg16(fd, 0x8D, SSD1306_CMD_PRECHARGE);
    gpioI2CWriteReg16(fd, 0x22, 0x8D); // 0x22

    // Set VCOM
    gpioI2CWriteReg16(fd, 0x8E, SSD1306_CMD_VCOMH);
    gpioI2CWriteReg16(fd, 0x05, 0x8E); // 0x05

    // Display on
    gpioI2CWriteReg16(fd, 0xAF, SSD1306_CMD_DISPLAYON);

    gpioTerminate();

    return 0;
}

void display_time(int i2c_address) {
    char buffer[10];
    struct tm *timeinfo;

    while (1) {
        time_t rawtime;
        time(&rawtime);
