    signal(SIGINT, signal_handler);

    // Initialize sensors
    int fd1 = init_sensor(SENSOR1_ADDR);
    int fd2 = init_sensor(SENSOR2_ADDR);
    int fd3 = init_sensor(SENSOR3_ADDR);

    if (fd1 == -1 || fd2 == -1 || fd3 == -1) {
        fprintf(stderr, "Error: Failed to initialize one or more sensors.\n");
        fclose(log_file);
        return 1;
    }

    // Main loop
    while (running) {
        int distance1 = read_distance(fd1);
        if (distance1 > 0) {
            printf("Sensor 1: %d mm\n", distance1);
            if (distance1 < WARNING_THRESHOLD) {
                trigger_warning(1, distance1);
            }
        }

        int distance2 = read_distance(fd2);
        if (distance2 > 0) {
            printf("Sensor 2: %d mm\n", distance2);
            if (distance2 < WARNING_THRESHOLD) {
                trigger_warning(2, distance2);
            }
        }

        int distance3 = read_distance(fd3);
        if (distance3 > 0) {
            printf("Sensor 3: %d mm\n", distance3);
            if (distance3 < WARNING_THRESHOLD) {
                trigger_warning(3, distance3);
            }
        }

        delay(50); // Small delay to avoid overloading the I2C bus
    }

    // Close the log file before exiting
    fclose(log_file);

    return 0;
}

