// VL53L1X Register Addresses (Example - Refer to Datasheet for complete list)
#define VL53L1X_REG_IDENTIFICATION_MODEL_ID 0x00c0
#define VL53L1X_REG_IDENTIFICATION_REVISION_ID 0x00c2
#define VL53L1X_REG_I2C_SLAVE_DEVICE_ADDRESS 0x008A
#define VL53L1X_REG_DISTANCE_RESULT 0x00FF

#define VL53L1X_DEFAULT_ADDRESS 0x29 // Default I2C address of VL53L1X

// Global variables
static int i2c_fd;
static FILE *log_file;
static volatile sig_atomic_t terminate = 0;

// Function prototypes
int vl53l1x_init(int fd);
int read_distance(int fd);
void log_distance(int distance);
void signal_handler(int signum);

// Signal handler function
void signal_handler(int signum) {
    if (signum == SIGINT || signum == SIGTERM) {
        fprintf(stderr, "\nReceived signal %d, terminating...\n", signum);
        terminate = 1;
    }
}

// VL53L1X Initialization function
int vl53l1x_init(int fd) {
    // Example initialization sequence (Refer to VL53L1X datasheet for complete initialization)
    // This is a simplified example and might need adjustments based on your specific setup.
    if (wiringPiI2CWriteReg8(fd, 0x0010, 0x04) < 0) { // Example register write
        perror("Error writing to VL53L1X");
        return -1;
    }
    if (wiringPiI2CWriteReg8(fd, 0x0014, 0x01) < 0) {
        perror("Error writing to VL53L1X");
        return -1;
    }
    if (wiringPiI2CWriteReg8(fd, 0x001E, 0x00) < 0) {
        perror("Error writing to VL53L1X");
        return -1;
    }
    if (wiringPiI2CWriteReg8(fd, 0x0024, 0x01) < 0) {
        perror("Error writing to VL53L1X");
        return -1;
    }
    if (wiringPiI2CWriteReg8(fd, 0x0026, 0x01) < 0) {
        perror("Error writing to VL53L1X");
        return -1;
    }
    if (wiringPiI2CWriteReg8(fd, 0x0027, 0x00) < 0) {
        perror("Error writing to VL53L1X");
        return -1;
    }

    // Start continuous ranging
    if (wiringPiI2CWriteReg8(fd, 0x0080, 0x03) < 0) { // MLX_REG_SYSRANGE_START
        perror("Error starting continuous ranging");
        return -1;
    }

    return 0;
}

// Function to read distance from VL53L1X
int read_distance(int fd) {
    int distance = -1; // Initialize to -1 to indicate failure

    // Read distance register
    int low = wiringPiI2CReadReg8(fd, VL53L1X_REG_DISTANCE_RESULT);
    int high = wiringPiI2CReadReg8(fd, VL53L1X_REG_DISTANCE_RESULT + 1);

    if (low < 0 || high < 0) {
        perror("Error reading distance data");
        return -1;
    }

    // Combine the two bytes to form the distance value
    distance = (high << 8) | low;

    // Check for errors
    if (distance < 0) {
        fprintf(stderr, "Invalid distance reading: %d\n", distance);
        return -1;
    }

    return distance;
}

// Function to log distance to file
void log_distance(int distance) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);

    if (log_file != NULL) {
        fprintf(log_file, "%d-%02d-%02d %02d:%02d:%02d, Distance: %d mm\n",
                tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday,
                tm.tm_hour, tm.tm_min, tm.tm_sec, distance);
        fflush(log_file); // Ensure data is written to disk immediately
    } else {
        fprintf(stderr, "Log file not opened.\n");
    }
}

int main() {
    // Set up signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize WiringPi I2C
    i2c_fd = wiringPiI2CSetup(VL53L1X_DEFAULT_ADDRESS);
    if (i2c_fd < 0) {
        perror("Error initializing I2C");
        return 1;
    }

    // Open log file
    log_file = fopen("distance_log.txt", "a");
    if (log_file == NULL) {
        perror("Error opening log file");
        return 1;
    }

    // Initialize VL53L1X sensor
    if (vl53l1x_init(i2c_fd) < 0) {
        fprintf(stderr, "VL53L1X initialization failed.\n");
        fclose(log_file);
        return 1;
    }

    printf("VL53L1X sensor initialized successfully. Logging distance data...\n");

    // Main loop
    while (!terminate) {
        int distance = read_distance(i2c_fd);
        if (distance >= 0) {
            log_distance(distance);

            // Warning condition
            if (distance < 200) {
                time_t t = time(NULL);
                struct tm tm = *localtime(&t);
                fprintf(stderr, "%d-%02d-%02d %02d:%02d:%02d - WARNING: Object detected within 200mm!\n",
                        tm.tm_year + 1900, tm.tm_mon + 1, tm.tm_mday,
                        tm.tm_hour, tm.tm_min, tm.tm_sec);
            }
        } else {
            fprintf(stderr, "Failed to read distance.\n");
        }

        delay(100); // Delay for 100ms
    }

    // Cleanup
    printf("Cleaning up...\n");
    if (i2c_fd >= 0) {
        close(i2c_fd);
    }
    if (log_file != NULL) {
        fclose(log_file);
    }

    printf("Exiting.\n");
    return 0;
}

