#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <math.h>
#include <errno.h>
#include <signal.h>
#include <wiringPi.h>

// Constants
#define I2C_DEVICE "/dev/i2c-1"
#define LSM303D_ADDR 0x19
#define CTRL_REG1_A 0x20
#define CTRL_REG4_A 0x23
#define OUT_X_L_A 0x28
#define OUT_X_H_A 0x29
#define OUT_Y_L_A 0x2A
#define OUT_Y_H_A 0x2B
#define OUT_Z_L_A 0x2C
#define OUT_Z_H_A 0x2D
#define LED_PIN 17
#define ACCEL_FS_2G 2.0f  // Full scale range +/- 2g
#define G_TO_RAW 16384.0f // Conversion factor for +/- 2g
#define THRESHOLD 1.5f
#define RETRY_COUNT 3

// Global variables
int i2c_fd;
bool running = true;

// Function prototypes
int i2c_write_byte(int fd, uint8_t reg, uint8_t value);
int i2c_read_byte(int fd, uint8_t reg, uint8_t *value);
int init_i2c(const char *device, int addr);
void config_accelerometer(int fd);
int16_t read_acceleration_axis(int fd, uint8_t low_reg, uint8_t high_reg);
float calculate_magnitude(int16_t x, int16_t y, int16_t z);
bool check_threshold(float magnitude);
void control_led(bool on);
void signal_handler(int signum);
void log_error(const char *message);

// I2C write function
int i2c_write_byte(int fd, uint8_t reg, uint8_t value) {
  int retries = RETRY_COUNT;
  while (retries > 0) {
    uint8_t buf[2] = {reg, value};
    if (write(fd, buf, 2) == 2) {
      return 0; // Success
    }
    log_error("I2C write failed. Retrying...");
    retries--;
    delay(1); // Small delay before retrying
  }
  log_error("I2C write failed after multiple retries.");
  return -1; // Failure
}

// I2C read function
int i2c_read_byte(int fd, uint8_t reg, uint8_t *value) {
  int retries = RETRY_COUNT;
  while (retries > 0) {
    if (write(fd, &reg, 1) == 1) {
      if (read(fd, value, 1) == 1) {
        return 0; // Success
      }
      log_error("I2C read data failed. Retrying...");
    } else {
      log_error("I2C write register address failed. Retrying...");
    }
    retries--;
    delay(1); // Small delay before retrying
  }
  log_error("I2C read failed after multiple retries.");
  return -1; // Failure
}

// Initialize I2C
int init_i2c(const char *device, int addr) {
  int fd = open(device, O_RDWR);
  if (fd < 0) {
    perror("Failed to open I2C device");
    log_error("Failed to open I2C device.");
    return -1;
  }
  if (ioctl(fd, I2C_SLAVE, addr) < 0) {
    perror("Failed to set I2C slave address");
    close(fd);
    log_error("Failed to set I2C slave address.");
    return -1;
  }
  return fd;
}

// Configure accelerometer
void config_accelerometer(int fd) {
  // Enable accelerometer, 100Hz data rate
  if (i2c_write_byte(fd, CTRL_REG1_A, 0x57) != 0) {
    log_error("Failed to write to CTRL_REG1_A");
  }

  // Set full scale range to +/- 2g
  if (i2c_write_byte(fd, CTRL_REG4_A, 0x00) != 0) {
    log_error("Failed to write to CTRL_REG4_A");
  }
}

// Read acceleration data for a single axis
int16_t read_acceleration_axis(int fd, uint8_t low_reg, uint8_t high_reg) {
  uint8_t low, high;
  if (i2c_read_byte(fd, low_reg, &low) != 0) {
    log_error("Failed to read low byte");
    return 0; // Return 0 as a default value
  }
  if (i2c_read_byte(fd, high_reg, &high) != 0) {
    log_error("Failed to read high byte");
    return 0; // Return 0 as a default value
  }
  return (int16_t)((high << 8) | low);
}

// Calculate the magnitude of the acceleration vector
float calculate_magnitude(int16_t x, int16_t y, int16_t z) {
  float x_g = (float)x / G_TO_RAW * ACCEL_FS_2G;
  float y_g = (float)y / G_TO_RAW * ACCEL_FS_2G;
  float z_g = (float)z / G_TO_RAW * ACCEL_FS_2G;
  return sqrt(x_g * x_g + y_g * y_g + z_g * z_g);
}

// Check if the acceleration magnitude exceeds the threshold
bool check_threshold(float magnitude) {
  return magnitude > THRESHOLD;
}

// Control the LED
void control_led(bool on) {
  digitalWrite(LED_PIN, on ? HIGH : LOW);
}

// Signal handler for graceful shutdown
void signal_handler(int signum) {
  if (signum == SIGINT) {
    printf("Received SIGINT, shutting down...\n");
    running = false;
    close(i2c_fd);
    digitalWrite(LED_PIN, LOW); // Turn off LED on exit

    exit(0);
  }
}

// Log errors to a file
void log_error(const char *message) {
  FILE *fp = fopen("/var/log/accelerometer.log", "a");
  if (fp != NULL) {
    fprintf(fp, "Error: %s (errno: %d, %s)\n", message, errno, strerror(errno));
    fclose(fp);
  }
  fprintf(stderr, "Error: %s (errno: %d, %s)\n", message, errno, strerror(errno));
}

int main() {
  // Initialize wiringPi
  if (wiringPiSetup() == -1) {
    fprintf(stderr, "Failed to initialize wiringPi\n");
    log_error("Failed to initialize wiringPi.");
    return 1;
  }

  // Set LED pin as output
  pinMode(LED_PIN, OUTPUT);

  // Initialize I2C
  i2c_fd = init_i2c(I2C_DEVICE, LSM303D_ADDR);
  if (i2c_fd < 0) {
    return 1;
  }

  // Configure accelerometer
  config_accelerometer(i2c_fd);

  // Set up signal handler for Ctrl+C
  signal(SIGINT, signal_handler);

  printf("Accelerometer monitoring started. Press Ctrl+C to exit.\n");

  // Main loop
  while (running) {
    // Read acceleration data
    int16_t x = read_acceleration_axis(i2c_fd, OUT_X_L_A, OUT_X_H_A);
