void read_acceleration_data(int16_t *x, int16_t *y, int16_t *z) {
    int x_l, x_h, y_l, y_h, z_l, z_h;

    x_l = wiringPiI2CReadReg8(i2c_fd, OUT_X_L_A);
    x_h = wiringPiI2CReadReg8(i2c_fd, OUT_X_H_A);
