// Define GPIO pins for tilt switches and LEDs
#define TILT_SWITCH_1 17
#define TILT_SWITCH_2 22
#define TILT_SWITCH_3 23

#define LED_1 18
#define LED_2 24
#define LED_3 25

// Debounce interval in milliseconds
#define DEBOUNCE_INTERVAL 50

// Global variables
volatile int running = 1;
pthread_mutex_t log_mutex;

// Function prototypes
int initialize_gpio();
int read_gpio(int pin);
int set_gpio(int pin, int value);
void interrupt_handler_1(int gpio, int level, uint32_t tick);
void interrupt_handler_2(int gpio, int level, uint32_t tick);
void interrupt_handler_3(int gpio, int level, uint32_t tick);
void log_event(int tilt_pin, int led_state);
