struct DebounceData debounce_data_2 = {0};
struct DebounceData debounce_data_3 = {0};

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
    cleanup();
    exit(0);
}

// Function to initialize pigpio and GPIO pins
int initialize_gpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1; // Indicate failure
    }

    // Set GPIO pins for tilt switches as input with pull-down resistors
    gpioSetMode(TILT_SWITCH_1, PI_INPUT);
    gpioSetMode(TILT_SWITCH_2, PI_INPUT);
    gpioSetMode(TILT_SWITCH_3, PI_INPUT);
    gpioSetPullUpDown(TILT_SWITCH_1, PI_PUD_DOWN);
    gpioSetPullUpDown(TILT_SWITCH_2, PI_PUD_DOWN);
    gpioSetPullUpDown(TILT_SWITCH_3, PI_PUD_DOWN);

    // Set GPIO pins for LEDs as output
    gpioSetMode(LED_1, PI_OUTPUT);
    gpioSetMode(LED_2, PI_OUTPUT);
    gpioSetMode(LED_3, PI_OUTPUT);

    // Initialize LEDs to OFF state
    set_gpio(LED_1, 0);
    set_gpio(LED_2, 0);
    set_gpio(LED_3, 0);

    // Set up interrupts for tilt switches
    gpioSetISRFunc(TILT_SWITCH_1, RISING_EDGE, DEBOUNCE_INTERVAL, interrupt_handler_1);
    gpioSetISRFunc(TILT_SWITCH_2, RISING_EDGE, DEBOUNCE_INTERVAL, interrupt_handler_2);
    gpioSetISRFunc(TILT_SWITCH_3, RISING_EDGE, DEBOUNCE_INTERVAL, interrupt_handler_3);

    return 0; // Indicate success
}

// Function to read the state of a GPIO pin
int read_gpio(int pin) {
    return gpioRead(pin);
}

// Function to set the state of a GPIO pin
int set_gpio(int pin, int value) {
