    return 0;
}

// Interrupt handler for tilt switch 1
void interrupt_handler_1(int gpio, int level, uint32_t tick) {
    static uint32_t last_tick = 0;
    if (tick - last_tick < DEBOUNCE_INTERVAL * 1000) return; //debounce
    last_tick = tick;

    int led_state = read_gpio(LED_1);
    led_state = !led_state; // Toggle LED state
    set_gpio(LED_1, led_state);
    log_event(TILT_SWITCH_1, led_state);
