// Function to log events to the file (thread-safe)
void log_event(int tilt_pin, int led_state) {
    pthread_mutex_lock(&log_mutex);

    FILE *fp = fopen("tilt_log.txt", "a");
    if (fp == NULL) {
        perror("Error opening log file");
        pthread_mutex_unlock(&log_mutex);
        return;
    }

    // Get current timestamp in ISO 8601 format
    time_t t = time(NULL);
    struct tm tm = *gmtime(&t);
    char timestamp[30];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%dT%H:%M:%S", &tm);
    struct timespec ts;
    clock_gettime(CLOCK_REALTIME, &ts);
    long milliseconds = ts.tv_nsec / 1000000;
    char formatted_timestamp[40];
    snprintf(formatted_timestamp, sizeof(formatted_timestamp), "%s.%03ldZ", timestamp, milliseconds);

    fprintf(fp, "%s, GPIO %d, LED State: %s\n", formatted_timestamp, tilt_pin, led_state ? "ON" : "OFF");
    fclose(fp);

    pthread_mutex_unlock(&log_mutex);
}

