    // Set all GPIO pins to input with pull-down resistors (safe state)
    gpioSetMode(LED_1, PI_INPUT);
    gpioSetMode(LED_2, PI_INPUT);
    gpioSetMode(LED_3, PI_INPUT);
    gpioSetPullUpDown(LED_1, PI_PUD_DOWN);
    gpioSetPullUpDown(LED_2, PI_PUD_DOWN);
