To create a smart irrigation system using a Raspberry Pi Zero W, the pigpio library, and an MCP3008 ADC, follow these steps:

### Step 1: Set Up Your Hardware

- **Relay Modules**: Connect the relays to GPIO pins 17, 18, 27, and 22.
- **MCP3008 ADC**: Connect the ADC to the Raspberry Pi Zero W. The soil moisture sensors will be connected to channels 0, 1, 2, and 3 of the MCP3008.

### Step 2: Install Required Libraries

Ensure you have the `pigpio` and `libmcp3008` libraries installed.

```bash
sudo apt-get update
sudo apt-get install libpigpio0-dev
git clone https://github.com/greiman/MCP3008.git
cd MCP3008
make
sudo make install
```

### Step 3: Write the C Program

Here is a sample C program that uses `pigpio` to control the relays and `MCP3008` to read the soil moisture levels. It logs the data to a JSON file.

```c
#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <mcp3008.h>

#define RELAY_PINS {17, 18, 27, 22}
#define NUM_ZONES 4
#define LOG_FILE "irrigation_log.json"

void log_to_json(const char *filename, int zone, int duration_ms) {
    FILE *file = fopen(filename, "a");
    if (!file) {
        perror("Failed to open file");
        return;
    }

    time_t now = time(NULL);
    struct tm *time_info = localtime(&now);

    fprintf(file, "{\"timestamp\": \"%d-%02d-%02dT%02d:%02d:%02d\", \"zone\": %d, \"duration\": %d}\n",
            time_info->tm_year + 1900, time_info->tm_mon + 1, time_info->tm_mday,
            time_info->tm_hour, time_info->tm_min, time_info->tm_sec, zone, duration_ms);

    fclose(file);
}

void read_moisture(int channel) {
    int value = readadc(channel);
    float voltage = value * 3.3 / 1024;
    printf("Channel %d: %d (%.2f V)\n", channel, value, voltage);
}

int main() {
    // Initialize GPIO
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Unable to initialize pigpio\n");
        exit(1);
    }

    // Setup relay pins as output
    for (int i = 0; i < NUM_ZONES; i++) {
        gpioSetMode(RELAY_PINS[i], PI_OUTPUT);
    }

    // Open MCP3008
    mcp3008_t *adc = mcp3008_init(0); // CE0
    if (!adc) {
        fprintf(stderr, "Failed to initialize MCP3008\n");
        return 1;
    }

    while (1) {
        int zones_active = 0;

        for (int i = 0; i < NUM_ZONES; i++) {
            int moisture = readadc(i);
            if (moisture > 500) { // Adjust threshold as needed
                gpioWrite(RELAY_PINS[i], 1);
                zones_active++;
            } else {
                gpioWrite(RELAY_PINS[i], 0);
            }
        }

        if (zones_active > 1) {
            // Log error if more than one zone is active
            fprintf(stderr, "Warning: More than one zone is active simultaneously!\n");
        }

        if (zones_active > 0) {
            // Simulate watering duration
            sleep(5); // Watering for 5 seconds
            int duration = 5000; // Duration in milliseconds

            // Log the event
            log_to_json(LOG_FILE, i, duration);
        }

        sleep(10); // Check every 10 seconds
    }

    // Cleanup
    for (int i = 0; i < NUM_ZONES; i++) {
        gpioWrite(RELAY_PINS[i], 0);
    }
    gpioTerminate();
    mcp3008_close(adc);

    return 0;
}
```

### Step 4: Compile and Run the Program

Compile the program with the following command:

```bash
gcc -o smart_irrigation smart_irrigation.c -lpigpio -lmcp3008
```

Run the program:

```bash
./smart_irrigation
```

