#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <pthread.h>
#include <unistd.h>
#include <getopt.h>
#include <pigpio.h>
#include <errno.h>

#define GPIO_PIN 17
#define BUFFER_SIZE 100

// Structure to store vibration event data
typedef struct {
    struct timespec timestamp;
    uint32_t duration_us;
} VibrationEvent;

// Circular buffer
VibrationEvent vibration_buffer[BUFFER_SIZE];
int buffer_index = 0;
int buffer_count = 0;

// Mutex and condition variable for thread synchronization
pthread_mutex_t buffer_mutex;
pthread_cond_t buffer_cond;

// Vibration threshold (microseconds)
uint32_t vibration_threshold = 1000; // Default value

// Debounce time (microseconds)
uint32_t debounce_time = 500; // Default value

// Flag to indicate program termination
volatile sig_atomic_t program_running = 1;

// File pointer for logging
FILE *log_file = NULL;

// Function prototypes
void vibration_callback(int gpio, int level, uint32_t tick, void *userdata);
void *logging_thread(void *arg);
void signal_handler(int signal);
void cleanup();

// Callback function for vibration events
void vibration_callback(int gpio, int level, uint32_t tick, void *userdata) {
    static uint32_t last_tick = 0;

    if (level == PI_LOW) { // Falling edge detected
        uint32_t current_tick = gpioTick();
        uint32_t duration_us = current_tick - last_tick;

        if (duration_us >= debounce_time) {
            if (duration_us >= vibration_threshold) {
                struct timespec ts;
                if (clock_gettime(CLOCK_REALTIME, &ts) == -1) {
                    perror("clock_gettime");
                    return;
                }

                // Lock the mutex before accessing the buffer
                pthread_mutex_lock(&buffer_mutex);

                // Store the vibration event in the circular buffer
                vibration_buffer[buffer_index].timestamp = ts;
                vibration_buffer[buffer_index].duration_us = duration_us;
                buffer_index = (buffer_index + 1) % BUFFER_SIZE;
                if (buffer_count < BUFFER_SIZE) {
                    buffer_count++;
                }

                // Signal the logging thread that new data is available
                pthread_cond_signal(&buffer_cond);

                // Unlock the mutex
                pthread_mutex_unlock(&buffer_mutex);
            }
        }
        last_tick = current_tick;
    }
}

// Logging thread function
void *logging_thread(void *arg) {
    while (program_running) {
        // Lock the mutex before accessing the buffer
        pthread_mutex_lock(&buffer_mutex);

        // Wait for a signal that new data is available or timeout after 5 seconds
        struct timespec ts;
        clock_gettime(CLOCK_REALTIME, &ts);
        ts.tv_sec += 5; // Timeout after 5 seconds
        int result = pthread_cond_timedwait(&buffer_cond, &buffer_mutex, &ts);

        // Check if timed wait expired without a signal, meaning no new data
        if (result == ETIMEDOUT && buffer_count == 0) {
            pthread_mutex_unlock(&buffer_mutex);
            continue; // Check if program is still running
        }

        // Write the contents of the circular buffer to the log file
        if (log_file != NULL) {
            int i = (buffer_index - buffer_count + BUFFER_SIZE) % BUFFER_SIZE;
            for (int j = 0; j < buffer_count; j++) {
                struct tm *tm_info;
                char timestamp_str[30];

                tm_info = localtime(&vibration_buffer[i].timestamp.tv_sec);
                strftime(timestamp_str, sizeof(timestamp_str), "%Y-%m-%d %H:%M:%S", tm_info);
                fprintf(log_file, "%s.%06ld: %u\n", timestamp_str, vibration_buffer[i].timestamp.tv_nsec / 1000, vibration_buffer[i].duration_us);
                i = (i + 1) % BUFFER_SIZE;
            }
            fflush(log_file); // Ensure data is written to disk
        }

        // Reset the buffer count
        buffer_count = 0;

        // Unlock the mutex
        pthread_mutex_unlock(&buffer_mutex);
    }

    pthread_exit(NULL);
}

// Signal handler function
void signal_handler(int signal) {
    program_running = 0;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
    cleanup();
    exit(0);
}

// Cleanup function to release resources
void cleanup() {
    // Stop pigpio
    gpioTerminate();

    // Destroy mutex and condition variable
    pthread_mutex_destroy(&buffer_mutex);
    pthread_cond_destroy(&buffer_cond);

    // Close the log file
    if (log_file != NULL) {
        fclose(log_file);
    }
}

int main(int argc, char *argv[]) {
    int opt;

    // Parse command-line arguments
    while ((opt = getopt(argc, argv, "t:d:")) != -1) {
        switch (opt) {
            case 't':
                vibration_threshold = atoi(optarg);
                break;
            case 'd':
                debounce_time = atoi(optarg);
                break;
            default:
                fprintf(stderr, "Usage: %s [-t threshold] [-d debounce]\n", argv[0]);
                return 1;
        }
    }

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO pin as input
    gpioSetMode(GPIO_PIN, PI_INPUT);

    // Initialize mutex and condition variable
    pthread_mutex_init(&buffer_mutex, NULL);
    pthread_cond_init(&buffer_cond, NULL);

    // Open the log file
    log_file = fopen("vibration_log.txt", "a");
    if (log_file == NULL) {
        perror("fopen");
        cleanup();
        return 1;
    }

    // Set up signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Create the logging thread
    pthread_t logging_thread_id;
    if (pthread_create(&logging_thread_id, NULL, logging_thread, NULL) != 0) {
        perror("pthread_create");
        cleanup();
        return 1;
    }

    // Set up the callback function for vibration events
    gpioSetAlertFuncEx(GPIO_PIN, vibration_callback, NULL);

    printf("Vibration monitoring system started. Press Ctrl+C to exit.\n");

    // Keep the main thread running
    while (program_running) {
        sleep(1); // Reduce CPU usage
    }

    // Wait for the logging thread to finish
    pthread_join(logging_thread_id, NULL);

    // Cleanup and exit
    cleanup();

    return 0;
}

