```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <pigpio.h>

#define VIBRATION_GPIO 17

// Function to initialize logging
void init_logging() {
    FILE *log_file = fopen("/var/log/vibration_shutdown.log", "a");
    if (log_file == NULL) {
        perror("Failed to open log file");
        exit(EXIT_FAILURE);
    }
    // Flush output buffer after every write
    setbuf(log_file, NULL);
}

// Callback function for the vibration sensor
void vibration_callback(unsigned gpio, unsigned level, uint32_t tick) {
    static int last_level = -1;
    static time_t last_time = 0;

    if (level != last_level) {
        time_t now = time(NULL);
        struct tm *tm_info = localtime(&now);

        char log_message[256];
        strftime(log_message, sizeof(log_message), "%Y-%m-%d %H:%M:%S", tm_info);
        if (level == PI_GPIO_HIGH) {
            sprintf(log_message + strlen(log_message), " Vibration detected on GPIO %d\n", gpio);
        } else {
            sprintf(log_message + strlen(log_message), " Vibration ended on GPIO %d\n", gpio);
        }

        fprintf(stderr, "%s", log_message);  // Print to console
        fprintf(stdout, "%s", log_message); // Print to log file
        fflush(stdout);  // Ensure the log message is written immediately
        fclose(stdout);  // Close stdout to avoid it being used again
        stdout = fopen("/dev/null", "w");  // Redirect stdout to /dev/null
        fprintf(stdout, "%s", log_message); // Write to /dev/null
        fclose(stdout);  // Close stdout
        stdout = fopen("/dev/tty", "w");   // Reopen stdout to console

        last_level = level;
        last_time = now;
    }
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        perror("pigpio initialization failed");
        return EXIT_FAILURE;
    }

    // Set up the vibration sensor
