#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <pigpio.h>
#include <time.h>

#define GATE_PIN 18  // GPIO pin controlling the gate (e.g., a relay)
#define SENSOR_ADDRESS 0x29  // I2C address of the VL53L1X sensor

// Function prototypes
int init_i2c(void);
void read_distance(int *distance);
void open_gate(void);
void close_gate(void);
void log_event(const char *event);

int main(void) {
    int i2c_fd;
    int distance = -1;
    int last_open_time = 0;
    int no_object_time = 0;

    // Initialize GPIO and I2C
    if (gpioInitialise() < 0) {
        fprintf(stderr, "Unable to initialize GPIO.\n");
        return 1;
    }

    if ((i2c_fd = init_i2c()) < 0) {
        fprintf(stderr, "Unable to initialize I2C.\n");
        return 1;
    }

    // Set up GPIO pin as output
    gpioSetMode(GATE_PIN, PI_OUTPUT);

    while (1) {
        // Read distance from sensor
        read_distance(&distance);

        // Check if an object is detected within 50cm
        if (distance <= 500) {  // Distance in mm, so 500mm = 50cm
            if (!no_object_time) {
                // Object detected, open gate
                open_gate();
                last_open_time = time(NULL);
                no_object_time = 0;
            } else {
                // Reset no object time
                no_object_time = 0;
            }
