    ssd1306_command(file, SSD1306_SET_COLUMN_ADDRESS);
    ssd1306_command(file, 0);       // Column start
    ssd1306_command(file, SSD1306_WIDTH-1); // Column end

    ssd1306_command(file, SSD1306_SET_PAGE_ADDRESS);
