    ssd1306_command(fd, SSD1306_DISPLAY_OFF);

    ssd1306_command(fd, SSD1306_SET_SEGMENT_REMAP | 0x01);   // Mirror segments
    ssd1306_command(fd, SSD1306_SET_COM_PINS | 0x12);       // 128 columns
