    ssd1306_command(fd, SSD1306_SET_DISPLAY_OFFSET | 0x00);  // Set display offset
    ssd1306_command(fd, SSD1306_SET_COM_SCAN_DIR | 0x00);    // Normal COM scan direction

    ssd1306_command(fd, SSD1306_SET_DISPLAY_START_LINE | 0x00); // Set display start line

    ssd1306_command(fd, SSD1306_CHARGEPUMP | 0x14); // Enable charge pump

    ssd1306_command(fd, SSD1306_SET_CHARGE_PUMP | 0x14); // Enable charge pump

    ssd1306_command(fd, SSD1306_DISPLAY_ON);

    // Clear the display
    ssd1306_clear_display(fd);

    // Display a white screen
    unsigned char whiteScreen[SSD1306_WIDTH/8] = {0xFF};
    ssd1306_write_row(fd, whiteScreen, SSD1306_WIDTH/8);

    delay(5000); // Wait 5 seconds

    // Turn off the display
    ssd1306_command(fd, SSD1306_DISPLAY_OFF);

    close(fd);
    return 0;
}

