                log_data("Too many accelerometer read errors, pausing plotting.\n");
                sleep(5); // Wait before retrying
                read_error_count = 0;
            }
        }

        gpioDelay(100000); // Small delay to prevent busy-waiting
    }

    // Stop motors (optional)
    gpioWrite(MOTOR0_IN1, 0);
    gpioWrite(MOTOR0_IN2, 0);
    gpioWrite(MOTOR0_IN3, 0);
    gpioWrite(MOTOR0_IN4, 0);
    gpioWrite(MOTOR1_IN1, 0);
    gpioWrite(MOTOR1_IN2, 0);
    gpioWrite(MOTOR1_IN3, 0);
    gpioWrite(MOTOR1_IN4, 0);

