#include "motor.h"

void motorAStep(int step) {
    int pins[] = {IN1_A, IN2_A, IN3_A, IN4_A};

    switch (step) {
        case 0: digitalWrite(pins[0], LOW); digitalWrite(pins[1], LOW); digitalWrite(pins[2], LOW); digitalWrite(pins[3], LOW); break;
