### Step 4: Generate Hilbert Curve Points

Create a file `hilbert_curve.h`:

```c
#ifndef HILBERT_CURVE_H
#define HILBERT_CURVE_H

#include <stdlib.h>

typedef struct {
    int x;
    int y;
} Point;

Point hilbertCurve(int level);

#endif // HILBERT_CURVE_H
```

And the implementation file `hilbert_curve.c`:

```c
#include "hilbert_curve.h"

Point hilbertCurve(int level) {
    if (level == 0) {
        return (Point){0, 0};
    }

    int size = 1 << (level - 1);
    Point p0 = hilbertCurve(level - 1);
    Point p1 = {p0.x + size, p0.y};

    Point result[4];
    result[0] = p0;
    result[1] = p1;
    result[2] = p1;
    result[3] = p0;

    for (int i = 0; i < 4; i++) {
        Point next = hilbertCurve(level - 1);
        next.x += p0.x + ((i & 1) ? size : 0);
        next.y += p0.y + ((i >= 2) ? size : 0);
        result[i].x = next.x;
        result[i].y = next.y;
    }

    return result[(level % 4)];
}
```

