    pinMode(IN4_B, OUTPUT);

    if (wiringPiSetupGpio() == -1) {
        printf("Failed to initialize wiringPi\n");
        return 1;
    }

    for (int level = 1; level <= 4; level++) {
        Point point = hilbertCurve(level);
        printf("Level %d: (%d, %d)\n", level, point.x, point.y);

        for (int i = 0; i < 4; i++) {
            int direction = i - (point.x % 2) + (point.y % 2) * 2;
            motorAStep(direction);
            motorBStep(direction);

            delayMicroseconds(DELAY);
        }
    }

    return 0;
}
```

