```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <wiringPiI2C.h>
#include <unistd.h>

#define SHT31_ADDR 0x44
#define SHT31_CMD_MEASURE_HIGH_REZ 0x2C
#define SHT31_CMD_MEASURE_HIGH_REZ_NO_WAIT 0x2C | 0x06
#define SHT31_CMD_SOFT_RESET 0x30

void writeCommand(int fd, int command) {
    wiringPiI2CWriteReg8(fd, 0x00, command);
}

int main() {
    int fd;
    char buffer[20];
    float temperature, humidity;

    // Initialize I2C communication
    if ((fd = wiringPiI2CSetup(SHT31_ADDR)) < 0) {
        perror("Failed to initialize I2C");
        return -1;
    }

    // Perform a soft reset to ensure the device is in a known state
    writeCommand(fd, SHT31_CMD_SOFT_RESET);

    // Wait for the reset to complete (approximately 15 ms)
    sleep(0.015);

    // Send the command to measure temperature and humidity at high resolution
    writeCommand(fd, SHT31_CMD_MEASURE_HIGH_REZ_NO_WAIT);

    // Read the response from the sensor
    if (wiringPiI2CReadReg16(fd, 0x00) != 0xFFFE) {
        printf("Error reading data from sensor\n");
        return -1;
    }

    // Read the raw temperature and humidity values
    wiringPiI2CReadReg16(fd, 0x00);
    wiringPiI2CReadReg16(fd, 0x02);

    // Convert the raw values to temperature and humidity
    temperature = (175.72 * wiringPiI2CReadReg16(fd, 0x00) / 65536) - 46.85;
    humidity = (100 * wiringPiI2CReadReg16(fd, 0x02) / 65536);

    // Create the JSON string
    char json_str[256];
    snprintf(json_str, sizeof(json_str), "{\"temperature\": %f, \"humidity\": %f}", temperature, humidity);

    // Write the JSON data to a file
    FILE *fp = fopen("environmental_log.json", "a");
    if (fp == NULL) {
        perror("Failed to open file for writing");
        return -1;
    }
    fprintf(fp, "%s\n", json_str);
    fclose(fp);

    return 0;
}
```

### Step 3: Compiling and Running the Program

Compile the program using the following command:

```bash
gcc -o sht31_logger sht31_logger.c -lwiringPi
```

Run the compiled program:

```bash
sudo ./sht31_logger
```

