#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <signal.h>
#include <syslog.h>
#include <unistd.h>

// Define GPIO pins
#define RELAY_PIN 17
#define SENSOR1_PIN 4
#define SENSOR2_PIN 5

// Debounce delay in milliseconds
#define DEBOUNCE_DELAY 50

// Global variable for relay state
volatile int relayState = 0; // 0 = OFF, 1 = ON

// Function prototypes
int readSensor(int pin);
void controlRelay(int state);
void logEvent(const char *message);
void cleanup(int signal);

// Signal handler for graceful exit
void cleanup(int signal) {
 syslog(LOG_INFO, "Received signal %d, cleaning up and exiting.", signal);
 digitalWrite(RELAY_PIN, LOW); // Ensure relay is OFF on exit
 syslog(LOG_INFO, "Relay turned OFF.");
 wiringPiSetupGpio(); // Reinitialize wiringPi to avoid conflicts
 pinMode(RELAY_PIN, INPUT); // Set the relay pin back to input mode.
 pinMode(SENSOR1_PIN, INPUT);
 pinMode(SENSOR2_PIN, INPUT);
 syslog(LOG_INFO, "GPIO pins released.");
 closelog();
 exit(0);
}

// Function to read sensor value with debouncing
int readSensor(int pin) {
 int reading = digitalRead(pin);
 delay(DEBOUNCE_DELAY);
 if (digitalRead(pin) != reading) {
 return digitalRead(pin); // Re-read to confirm
 }
 return reading;
}

// Function to control the relay
void controlRelay(int state) {
 digitalWrite(RELAY_PIN, state);
 relayState = state;
 if (state == HIGH) {
 logEvent("Relay turned ON.");
 } else {
 logEvent("Relay turned OFF.");
 }
}

// Function to log events to syslog
void logEvent(const char *message) {
 syslog(LOG_INFO, "%s", message);
}

int main() {
 // Open syslog connection
 openlog("relay_controller", LOG_PID, LOG_USER);

 // Register signal handlers
 signal(SIGINT, cleanup);
 signal(SIGTERM, cleanup);

 // Initialize wiringPi using GPIO numbering
 if (wiringPiSetupGpio() == -1) {
 syslog(LOG_ERR, "wiringPiSetupGpio failed, exiting.");
 fprintf(stderr, "wiringPiSetupGpio failed, exiting.\n");
