Certainly! Below is a C program designed for the Raspberry Pi 3 Model B+ that uses the `pigpio` library to detect motion from an HC-SR501 PIR sensor and activates a buzzer connected to GPIO 27. The program logs timestamps of motion detections to a file named `motion_log.txt`.

First, ensure you have the `pigpio` library installed. You can install it via your package manager or by building from source.

Here is the C program:

```c
#include <stdio.h>
#include <stdlib.h>
#include <pigpio.h>
#include <time.h>

#define PIR_PIN 17
#define BUZZER_PIN 27
#define LOG_FILE "motion_log.txt"
#define LOG_INTERVAL 1000000  // 1 second in microseconds

int main() {
    int pi, event;
    long last_event_time;

    // Initialize pigpio
    pi = pigpio_start(NULL, NULL);
    if (pi < 0) {
        fprintf(stderr, "Failed to initialize pigpio: %s\n", pigpio_error(pi));
        return 1;
    }

    // Set PIR pin as input and enable edge detection
    if (gpiosetwavegen(PIR_PIN, 0) != PI_SUCCESS) {
        fprintf(stderr, "Failed to set PIR pin as input: %s\n", pigpio_error(pi));
        pigpio_stop(pi);
        return 1;
    }
    if (gpioedge(PIR_PIN, 1) != PI_SUCCESS) {
        fprintf(stderr, "Failed to enable edge detection on PIR pin: %s\n", pigpio_error(pi));
        pigpio_stop(pi);
        return 1;
    }

    // Set buzzer pin as output
    if (gpiosetwavegen(BUZZER_PIN, 0) != PI_SUCCESS) {
        fprintf(stderr, "Failed to set buzzer pin as output: %s\n", pigpio_error(pi));
        pigpio_stop(pi);
        return 1;
    }

    // Initialize last event time
    last_event_time = 0;

    while (1) {
        // Wait for an edge event on the PIR pin
        event = gpioeventget(pi, PIR_PIN);
        if (event < 0) {
            fprintf(stderr, "Failed to get event: %s\n", pigpio_error(pi));
            pigpio_stop(pi);
            return 1;
        }

        // Check if there was a rising edge (motion detected)
        if (event & GPIO_RISING_EDGE) {
            // Get current time in microseconds
            long current_time = gpioTick();
            if (current_time - last_event_time > LOG_INTERVAL) {
                // Log the timestamp
                FILE *log_file;
                log_file = fopen(LOG_FILE, "a");
                if (log_file == NULL) {
                    fprintf(stderr, "Failed to open log file: %s\n", pigpio_error(pi));
                    pigpio_stop(pi);
                    return 1;
                }

                // Write timestamp to log file
                fprintf(log_file, "%ld\n", current_time);
                fclose(log_file);

                // Activate buzzer for 1 second
                gpioPWM(BUZZER_PIN, 50);  // 50% duty cycle
                gpioDelay(1000000);       // 1 second delay
                gpioPWM(BUZZER_PIN, 0);   // Stop PWM

                // Update last event time
                last_event_time = current_time;
            }
        }
    }

    // Clean up
    pigpio_stop(pi);

    return 0;
}
```

### Explanation:
- **Pigpio Initialization**: The `pigpio_start` function initializes the pigpio library. If it fails, the program prints an error message and exits.
- **GPIO Setup**: The PIR sensor is configured as an input with edge detection enabled. The buzzer is configured as an output.
- **Main Loop**: The program enters an infinite loop where it waits for an edge event on the PIR sensor. When a rising edge is detected (indicating motion), the current time is recorded in microseconds. If enough time has passed since the last event, the timestamp is logged to `motion_log.txt` and the buzzer is activated for 1 second.
- **Error Handling**: The program includes error handling for various operations such as initializing pigpio, setting up GPIO pins, and logging events.

### Compilation and Running:
To compile this program, you can use the following command:

```sh
gcc -o motion_sensor motion_sensor.c -lpigpio
```

Then run the compiled binary:

```sh
./motion_sensor
```

