    // Initialize pigpio
    if (gpioInitialise() < 0) {
        perror("pigpio initialization failed");
        return 1;
    }

    // Set up the PIR sensor pin as input
    if (gpioSetMode(SENSOR_PIN, PI_INPUT) != PI_OK) {
        perror("Failed to set sensor pin as input");
        gpioTerminate();
        return 1;
    }

    // Set up the LED pin as output
    if (gpioSetMode(LED_PIN, PI_OUTPUT) != PI_OK) {
        perror("Failed to set LED pin as output");
        gpioTerminate();
        return 1;
    }

    // Set the LED pin low initially
    if (gpioWrite(LED_PIN, 0) != PI_OK) {
        perror("Failed to set initial LED state");
        gpioTerminate();
        return 1;
    }

    printf("PIR Motion Sensor and LED Blinking Program Running...\n");

    // Wait for motion
