        gpioTerminate();
        return 1;
    }

    // Initialize PIR sensor
    if (init_pir_sensor() != 0) {
        fprintf(stderr, "Failed to initialize PIR sensor.\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Initialize VL53L1X sensor
    if (init_vl53l1x() != 0) {
        fprintf(stderr, "Failed to initialize VL53L1X sensor.\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Open log file in append mode
    log_file = fopen("distance_log.csv", "a");
    if (log_file == NULL) {
        fprintf(stderr, "Failed to open log file.\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (!terminate) {
        // Read PIR sensor
        if (gpioRead(PIR_GPIO) == 1) {
            // Motion detected, read distance
            int distance = read_distance();
            if (distance >= 0) {
                log_data(distance);
                printf("Distance: %d mm\n", distance);
            } else {
                fprintf(stderr, "Failed to read distance.\n");
            }
        }
        gpioDelay(100); // Delay to avoid excessive CPU usage
    }

    // Close resources before exiting
    fclose(log_file);
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
