To create a C program for the Raspberry Pi Zero W that uses the pigpio library to implement a proximity-based musical doorbell with an HC-SR04 ultrasonic sensor and a piezo buzzer, follow these steps:

1. **Set up the environment**: Ensure you have the pigpio library installed. You can install it using `sudo apt-get install pigpio`.

2. **Create the C program**: Below is the complete code for the program.

```c
#include <pigpio.h>
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <string.h>

// Define constants
#define TRIGGER_PIN 17
#define ECHO_PIN 18
#define BUZZER_PIN 27
#define MIN_DISTANCE 20
#define MAX_DISTANCE 50

// Predefined melodies (in Hz)
int melody1[] = {262, 294, 330, 349, 392}; // C4, D4, E4, F4, G4
int melody2[] = {262, 294, 330, 262, 294}; // C4, D4, E4, C4, D4
int melody3[] = {392, 349, 330, 294, 262}; // G4, F4, E4, D4, C4

// Function prototypes
void setupPins();
void playMelody(int *melody, int size);
int getDistance();

int main(void) {
    int distance;
    int volume;

    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    setupPins();

    while (1) {
        distance = getDistance();

        if (distance < MIN_DISTANCE) {
            volume = 100; // Full volume
            playMelody(melody1, sizeof(melody1) / sizeof(int));
        } else if (distance >= MIN_DISTANCE && distance <= MAX_DISTANCE) {
            volume = 75; // Medium volume
            playMelody(melody2, sizeof(melody2) / sizeof(int));
        } else {
            volume = 50; // Low volume
            playMelody(melody3, sizeof(melody3) / sizeof(int));
        }

        gpioPWM(BUZZER_PIN, volume); // Set volume
        sleep(1);
    }

    gpioTerminate();
    return 0;
}

void setupPins() {
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioSetMode(BUZZER_PIN, PI_OUTPUT);
    gpioPWM(BUZZER_PIN, 0); // Turn off buzzer initially
}

int getDistance() {
    gpioSetMode(TRIGGER_PIN, PI_OUTPUT);
    gpioWrite(TRIGGER_PIN, 0);
    usleep(2);
    gpioWrite(TRIGGER_PIN, 1);
    usleep(10);
    gpioWrite(TRIGGER_PIN, 0);

    uint32_t pulseWidth = 0;
    gpioSetMode(ECHO_PIN, PI_INPUT);
    gpioDelay(1000); // Wait for the signal to be captured
    pulseWidth = gpioTimeWait(ECHO_PIN, 0, 1000000);

    if (pulseWidth == 0) {
        return -1; // Error: No signal received
    }

    float duration = pulseWidth / 58.0; // Convert microseconds to cm
    return (int)(duration);
}

void playMelody(int *melody, int size) {
    for (int i = 0; i < size; i++) {
        gpioTone(BUZZER_PIN, melody[i]);
        sleep(0.25); // Duration of each note in seconds
    }
}
