```c
#include <wiringPiI2C.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <errno.h>

#define BME280_ADDRESS 0x76
#define LOG_FILE "sensor_data.log"
#define STATE_FILE "sensor_state.dat"

// Function prototypes
void logDataToFile(double temp, double hum);
int restoreState(int *temp, int *hum);

int main(void) {
    int fd;
    int temp, hum;
    char buffer[50];

    // Restore the last known state if available
    if (restoreState(&temp, &hum) == 0) {
        printf("Restored state: Temperature = %d C, Humidity = %d %%\n", temp, hum);
    } else {
        printf("Failed to restore state.\n");
    }

    // Open the I2C device
    if ((fd = wiringPiI2CSetup(BME280_ADDRESS)) < 0) {
        fprintf(stderr, "Error opening I2C device: %s\n", strerror(errno));
        return 1;
    }

    while (1) {
        // Read temperature and humidity
        wiringPiI2CReadReg16(fd, 0xF7); // Start sequence for temperature
        wiringPiI2CReadReg16(fd, 0xF3); // Start sequence for humidity
        wiringPiI2CReadReg16(fd, 0xFA); // Read temperature MSB
        wiringPiI2CReadReg16(fd, 0xFB); // Read temperature LSB
        wiringPiI2CReadReg16(fd, 0xFC); // Read temperature XLSB
        wiringPiI2CReadReg16(fd, 0xFD); // Read humidity MSB
        wiringPiI2CReadReg16(fd, 0xFE); // Read humidity LSB

