        double rawTemp = (double)(wiringPiI2CReadReg16(fd, 0xFA) << 12 | wiringPiI2CReadReg16(fd, 0xFB) << 4 | wiringPiI2CReadReg16(fd, 0xFC) >> 4) / 16384.0;
