        logDataToFile(temperature, humidity);

        // Update the state file with the current readings
        if (restoreState(&temp, &hum) == 0) {
            temp = temperature;
            hum = humidity;
            snprintf(buffer, sizeof(buffer), "%d %d", temp, hum);
            FILE *stateFile = fopen(STATE_FILE, "w");
            if (stateFile) {
                fprintf(stateFile, "%s", buffer);
                fclose(stateFile);
            }
        }

        // Sleep for 1 second before next reading
        sleep(1);
    }

    return 0;
}

void logDataToFile(double temp, double hum) {
    FILE *logFile = fopen(LOG_FILE, "a");
    if (logFile) {
        time_t now = time(NULL);
        struct tm *tmInfo = localtime(&now);
        char timestamp[20];
        strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", tmInfo);

        fprintf(logFile, "%s,%.2f,%.2f\n", timestamp, temp, hum);
        fclose(logFile);
