2. **Initialize the Display**: Use the appropriate functions from the `pigpio` library to initialize the SSD1306 display.
3. **Send Data to the Display**: Write the necessary commands and data to the display to show the text 'Hello, OLED!'.

Below is a complete example of a C program that initializes an SSD1306 OLED display connected via I2C and displays the text 'Hello, OLED!' on it.

### Step 1: Install Pigpio

First, install the `pigpio` library and its development files. You can do this by running the following commands in your terminal:

```sh
sudo apt-get update
sudo apt-get install pigpio python-pigpio
```

### Step 2: Write the C Program

Here is the C program to initialize an SSD1306 OLED display and display the text 'Hello, OLED!':

```c
#include <stdio.h>
#include <pigpio.h>

// Constants for I2C communication with SSD1306
#define SSD1306_I2C_ADDRESS 0x3C
#define SSD1306_SETCONTRAST 0x81
#define SSD1306_DISPLAYALLON_RESUME 0xA4
#define SSD1306_NORMALDISPLAY 0xA6
#define SSD1306_DISPLAYOFF 0xAE
#define SSD1306_DISPLAYON 0xAF
#define SSD1306_SETDISPLAYOFFSET 0xD3
#define SSD1306_SETSTARTLINE 0x40
#define SSD1306_CHARGEPUMP 0x8D
#define SSD1306_MEMORYMODE 0x20
#define SSD1306_COLUMNADDR 0x21
#define SSD1306_PAGEADDR 0x22
#define SSD1306_COMSCANINC 0xC0
#define SSD1306_COMSCANDEC 0xC8
#define SSD1306_SETCOMPINS 0xDA
#define SSD1306_SETVCOMDETECT 0xDB
#define SSD1306_SETDISPLAYCLOCKDIV 0xD5
#define SSD1306_SETPRECHARGE 0xD9
#define SSD1306_SETMULTIPLEX 0xA8
#define SSD1306_SETLOWCOLUMN 0x00
#define SSD1306_SETHIGHCOLUMN 0x10
#define SSD1306_SETDISPLAYOFFSET 0xD3
#define SSD1306_SETDISPLAYOFFSET 0xD3
#define SSD1306_SETSTARTLINE 0x40
#define SSD1306_SSD1306.WriteAll 0x75

void initOLED(void) {
    gpioInitialise(); // Initialize GPIO

    // Set the I2C bus speed
    gpioSetMode(1, PI_OUTPUT); // SDA (GPIO 2)
    gpioSetMode(2, PI_OUTPUT); // SCL (GPIO 3)

    // Initialize the display
    gpioWrite(1, 0); // SDA low
    gpioWrite(2, 0); // SCL low
    delayMicroseconds(10);
    gpioWrite(1, 1); // SDA high
    gpioWrite(2, 1); // SCL high
    delayMicroseconds(10);

    // Send start condition
    gpioWrite(1, 0); // SDA low
    gpioWrite(2, 0); // SCL low
    delayMicroseconds(10);
    gpioWrite(2, 1); // SCL high
    delayMicroseconds(10);
    gpioWrite(1, 1); // SDA high
    delayMicroseconds(10);
    gpioWrite(2, 0); // SCL low
    delayMicroseconds(10);
    gpioWrite(1, 0); // SDA low

    // Send address (0x3C)
    gpioWrite(2, 1); // SCL high
    delayMicroseconds(10);
    gpioWrite(1, 1); // SDA high
    gpioWrite(1, 0); // SDA low
    gpioWrite(2, 0); // SCL low
    gpioWrite(1, 1); // SDA high
    gpioWrite(1, 0); // SDA low
    gpioWrite(2, 1); // SCL high
    gpioWrite(1, 1); // SDA high
    gpioWrite(1, 0); // SDA low
    gpioWrite(2, 0); // SCL low
    gpioWrite(1, 1); // SDA high
    gpioWrite(1, 0); // SDA low

    // Send command
    gpioWrite(2, 1); // SCL high
    delayMicroseconds(10);
    gpioWrite(1, 1); // SDA high
    gpioWrite(1, 0); // SDA low
    gpioWrite(2, 0); // SCL low
    gpioWrite(1, 1); // SDA high
    gpioWrite(1, 0); // SDA low
    gpioWrite(2, 1); // SCL high
    gpioWrite(1, 1); // SDA high
    gpioWrite(1, 0); // SDA low
    gpioWrite(2, 0); // SCL low
    gpioWrite(1, 0); // SDA low
    gpioWrite(2, 1); // SCL high
    gpioWrite(1, 0); // SDA low
    gpioWrite(2, 0); // SCL low

    // Set display parameters
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_DISPLAYCONTROL, 0x00);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_DISPLAYALLON_RESUME, 0x00);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_NORMALDISPLAY, 0x00);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_DISPLAYOFF, 0x00);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_SETDISPLAYCLOCKDIV, 0x80);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_SETPRECHARGE, 0x22);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_SETMULTIPLEX, 0x3F);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_SETDISPLAYOFFSET, 0x00);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_SETSTARTLINE | 0x00, 0x00);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_CHARGEPUMP, 0x14);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_MEMORYMODE, 0x00);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_COLUMNADDR, 0x00);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_COLUMNADDR + 1, 0x3F);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_PAGEADDR, 0x00);
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_PAGEADDR + 1, 0x07);

    // Turn the display on
    i2cWriteReg8(SSD1306_I2C_ADDRESS, SSD1306_DISPLAYON, 0x00);
