    // Clear the display buffer
    memset(data, 0, sizeof(data));

    // Write the text to the buffer
    while (*text) {
        data[i++] = *text++;
    }

    // Send the buffer to the display
    i2cWriteReg8(SSD1306_I2C_ADDRESS, 0xB0, 0x00); // Start page address
    i2cWriteReg8(SSD1306_I2C_ADDRESS, 0x40, 0x00); // Column address
    i2cWriteReg8(SSD1306_I2C_ADDRESS, 0x00, 0x00); // Page address
    i2cWriteReg8(SSD1306_I2C_ADDRESS, 0x00, 0x00); // Column address
    i2cWriteReg8(SSD1306_I2C_ADDRESS, 0x40, 0x00); // Page address
    i2cWriteReg8(SSD1306_I2C_ADDRESS, 0xB0, 0x00); // Start page address

