To achieve this task, we'll need to write a C program that interacts with the BH1750 light sensor through I2C to read the ambient light levels and adjust the brightness of an LED strip connected to GPIO24. We'll use the `pigpio` library for controlling the LED strip and logging the data.

First, ensure you have the `pigpio` library installed on your Raspberry Pi. You can install it via the following command:

```sh
sudo apt-get update
sudo apt-get install pigpio python-pigpio
```

Now, let's write the C program:

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <errno.h>
#include <pigpio.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>

#define I2C_ADDRESS 0x23 // BH1750 I2C address
#define LED_PIN 24

int fd;

void init_i2c() {
    fd = open("/dev/i2c-1", O_RDWR);
    if (fd < 0) {
        perror("Failed to open I2C bus");
        exit(EXIT_FAILURE);
    }

    if (ioctl(fd, I2C_SLAVE, I2C_ADDRESS) < 0) {
        perror("Failed to acquire bus access and/or talk to slave.");
        close(fd);
        exit(EXIT_FAILURE);
    }
}

uint16_t read_lux() {
    char buf[2];
    uint16_t lux;

    if (write(fd, "\x81", 1) != 1) {
        perror("Error writing to BH1750");
        return -1;
    }

    usleep(150);

    if (read(fd, buf, 2) != 2) {
        perror("Error reading from BH1750");
        return -1;
    }

    lux = ((buf[0] << 8) | buf[1]) >> 2;

    return lux;
}

void set_led_brightness(int brightness) {
    gpioPWM(LED_PIN, brightness);
}

int main() {
    int lux, last_lux = 0, diff;

    if (gpioInitialise() < 0) {
        fprintf(stderr, "Unable to initialize GPIO\n");
        return 1;
    }

    gpioSetMode(LED_PIN, PI_OUTPUT);
    init_i2c();

    FILE *file = fopen("light_log.txt", "a");
    if (!file) {
        perror("Failed to open file for logging");
        return 1;
    }

    while (1) {
        lux = read_lux();
        if (lux == -1) {
            continue;
        }

        diff = abs(lux - last_lux);
        if (diff >= 5) {
            fprintf(file, "%s %d\n", ctime(&time(NULL)), lux);
            last_lux = lux;
        }

        set_led_brightness(lux);
        usleep(100000); // Sleep for 100ms
    }

    fclose(file);
    gpioTerminate();
    close(fd);

    return 0;
}
```

