#include <stdio.h>
#include <bcm2835.h>
#include <stdint.h>

// MCP4725 I2C address
#define MCP4725_ADDR 0x62

// Function to set the DAC output voltage
int set_dac_voltage(uint16_t voltage)
{
    // Create the 16-bit data to send.  The upper 4 bits are control bits, 
    // and the lower 12 bits are the DAC value.
    uint16_t data = (voltage & 0x0FFF) | 0x4000;  // Vout = voltage, write Vout
    uint8_t tx_buf[2];
    tx_buf[0] = (data >> 8) & 0xFF; // MSB
    tx_buf[1] = data & 0xFF;      // LSB

    // Begin I2C transmission
    bcm2835_i2c_begin();
    bcm2835_i2c_setSlaveAddress(MCP4725_ADDR);
    bcm2835_i2c_write(tx_buf, 2);
    bcm2835_i2c_end();

    return 0;
}

int main(int argc, char **argv)
{
    // Initialize bcm2835
    if (!bcm2835_init())
    {
        fprintf(stderr, "bcm2835_init failed. Are you running as root?\n");
        return 1;
    }

    // Configure I2C
    bcm2835_i2c_begin();
    bcm2835_i2c_setClockDivider(BCM2835_I2C_CLOCK_DIVIDER_626); // 100kHz

    // Set the DAC voltage (example: 2.5V assuming VREF = 3.3V, 12-bit DAC)
    // Voltage = (DAC_value / 4096) * VREF
    // DAC_value = (Voltage * 4096) / VREF
    // For 2.5V, DAC_value = (2.5 * 4096) / 3.3 = 3096.96 (approx. 3097)
    uint16_t dac_value = 3097;

    if (set_dac_voltage(dac_value) != 0)
    {
        fprintf(stderr, "Failed to set DAC voltage.\n");
        bcm2835_close();
        return 1;
    }

    printf("DAC voltage set to approximately 2.5V.\n");

    // Close bcm2835
    bcm2835_close();

    return 0;
}

