    // MCP4725 output range is 0V to 5V
    return (uint16_t)(voltage * 4095.0f / 5.0f);
}

int main() {
    // Initialize bcm2835 library
    if (!bcm2835_init()) {
        fprintf(stderr, "Failed to initialize BCM2835 library.\n");
        return 1;
