    // Initialize I2C interface
    if (!bcm2835_i2c_start()) {
        fprintf(stderr, "Failed to start I2C transaction.\n");
        bcm2835_close();
        return 1;
    }

    // Write command to select the DAC output register
    if (!bcm2835_i2c_write(MCP4725_DAC_OUTPUT)) {
        fprintf(stderr, "Failed to write command to DAC output register.\n");
        bcm2835_close();
        return 1;
    }

    // Write MSB first (16-bit data)
    uint16_t dac_value = voltage_to_dac_value(2.5); // Set to 2.5V
    uint8_t msb = (dac_value >> 8) & 0xFF;
    uint8_t lsb = dac_value & 0xFF;

    if (!bcm2835_i2c_write(msb) || !bcm2835_i2c_write(lsb)) {
        fprintf(stderr, "Failed to write DAC values.\n");
        bcm2835_close();
        return 1;
    }

    // Send stop condition
    if (!bcm2835_i2c_stop()) {
        fprintf(stderr, "Failed to send stop condition.\n");
        bcm2835_close();
        return 1;
    }

    // Write to the device
    if (!bcm2835_i2c_write(MCP4725_ADDRESS << 1 | I2C_WRITE)) {
        fprintf(stderr, "Failed to write to MCP4725.\n");
        bcm2835_close();
        return 1;
    }

    // Close I2C bus
    bcm2835_i2c_end();
    bcm2835_close();

    printf("DAC set to 2.5V\n");

    return 0;
}

