```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <pigpio.h>
#include <sht3x.h>
#include <LiquidCrystal_I2C.h>
#include <json-c/json.h>

#define SHT3X_I2C_ADDR 0x44
#define LCD_I2C_ADDR 0x27
#define LCD_COLUMNS 16
#define LCD_ROWS 2

int main() {
    int fd;
    uint16_t temp, hum;
    char json_buffer[512];
    json_object *json_obj;

    // Initialize GPIO
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialization failed\n");
        return -1;
    }

    // Initialize I2C for SHT31
    if (i2cOpen(1, SHT3X_I2C_ADDR, 0) < 0) {
        fprintf(stderr, "SHT31 I2C initialization failed\n");
        gpioTerminate();
        return -1;
    }

    // Initialize I2C for LCD1602
    LiquidCrystal_I2C lcd(LCD_I2C_ADDR, LCD_COLUMNS, LCD_ROWS);

    // Initialize LCD
    if (!lcd.begin(LCD_COLUMNS, LCD_ROWS)) {
        fprintf(stderr, "LCD initialization failed\n");
        i2cClose(i2cOpen(1, SHT3X_I2C_ADDR, 0));
        gpioTerminate();
        return -1;
    }

    // Set up LCD for output
    lcd.backlight();
    lcd.setCursor(0, 0);
    lcd.print("Humidity Sensor");

    // Main loop
    while (1) {
        // Read data from SHT31
        if (sht3xRead(&temp, &hum) != 0) {
            fprintf(stderr, "SHT31 read error\n");
            continue;
        }

        // Convert humidity to percentage
        float humidity = hum / 100.0;

        // Print to LCD
        lcd.setCursor(0, 1);
        lcd.print("Humidity: ");
        lcd.print(humidity);
        lcd.print("%");

        // Create JSON object
        json_obj = json_object_new_object();
        json_object_object_add(json_obj, "timestamp", json_object_new_string(__TIME__));
        json_object_object_add(json_obj, "humidity", json_object_new_double(humidity));

        // Convert JSON object to string
        json_object_to_json_string_ext(json_obj, json_buffer, sizeof(json_buffer), JSON_C_TO_STRING_PRETTY);

        // Log to file
        FILE *file = fopen("humidity_log.json", "a");
        if (file == NULL) {
            fprintf(stderr, "Failed to open log file\n");
            continue;
        }
        fprintf(file, "%s\n", json_buffer);
        fclose(file);

        // Sleep for 1 second
        sleep(1);
    }

    // Cleanup
    i2cClose(i2cOpen(1, SHT3X_I2C_ADDR, 0));
    lcd.noBacklight();
    lcd.clear();
    gpioTerminate();

    return 0;
}
```

