#include <pigpio.h>
#include <jansson.h>
#include <errno.h>

// Define constants
#define SHT31_ADDR 0x44
#define LCD_ADDR 0x27
#define LCD_WIDTH 16
#define LCD_HEIGHT 2

// Global variables
int i2c_handle_sht31;
int i2c_handle_lcd;
volatile sig_atomic_t terminate = 0;

// Function prototypes
void signal_handler(int signal);
int initialize_i2c_sht31();
int initialize_i2c_lcd();
void close_i2c_connections();
int sht31_read_data(float *temperature, float *humidity);
int lcd_init();
void lcd_send_byte(int bits);
void lcd_send_command(unsigned char command);
void lcd_send_data(unsigned char data);
void lcd_clear();
void lcd_print(const char *text);
void format_json_data(float temperature, float humidity, char *json_string, size_t json_string_size);
int log_humidity_data(const char *json_string);

// Signal handler function
void signal_handler(int signal) {
    fprintf(stderr, "Signal received, terminating...");
    terminate = 1;
}

// Initialize I2C connection to SHT31 sensor
int initialize_i2c_sht31() {
    i2c_handle_sht31 = i2cOpen(1, SHT31_ADDR, 0); // Bus 1, address 0x44, flags 0
    if (i2c_handle_sht31 < 0) {
        fprintf(stderr, "Error opening I2C device for SHT31: %s\n", strerror(errno));
        return -1;
    }
    return 0;
}

// Initialize I2C connection to LCD1602
int initialize_i2c_lcd() {
    i2c_handle_lcd = i2cOpen(1, LCD_ADDR, 0); // Bus 1, address 0x27, flags 0
    if (i2c_handle_lcd < 0) {
        fprintf(stderr, "Error opening I2C device for LCD: %s\n", strerror(errno));
        return -1;
    }

    // Initialize LCD (common configuration)
    lcd_clear(); // Clear display
    gpioDelay(50); // Wait 50ms
    lcd_send_command(0x38); // 2 lines, 5x8 font
    gpioDelay(5);       // Wait 5ms
    lcd_send_command(0x0C); // Display ON, cursor OFF, blink OFF
    gpioDelay(2);       // Wait 2ms
    lcd_send_command(0x06); // Increment cursor, no shift
    gpioDelay(2);       // Wait 2ms

    return 0;
}

// Close I2C connections
void close_i2c_connections() {
    if (i2c_handle_sht31 >= 0) {
        i2cClose(i2c_handle_sht31);
    }
    if (i2c_handle_lcd >= 0) {
        i2cClose(i2c_handle_lcd);
    }
    gpioTerminate();
}

// Read temperature and humidity from SHT31 sensor
int sht31_read_data(float *temperature, float *humidity) {
    unsigned char write_buffer[2] = {0x24, 0x00}; // Measurement mode: High repeatability, clock stretching enabled
    unsigned char read_buffer[6];

    if (i2cWriteDevice(i2c_handle_sht31, (char *)write_buffer, 2) != 2) {
        fprintf(stderr, "Error writing to SHT31: %s\n", strerror(errno));
        return -1;
    }

    gpioDelay(10); // Wait for measurement (at least 10ms)

    if (i2cReadDevice(i2c_handle_sht31, (char *)read_buffer, 6) != 6) {
        fprintf(stderr, "Error reading from SHT31: %s\n", strerror(errno));
        return -1;
    }

    // Convert data
    int temp_raw = (read_buffer[0] << 8) | read_buffer[1];
    int hum_raw = (read_buffer[3] << 8) | read_buffer[4];

    *temperature = -45.0 + (175.0 * (float)temp_raw / 65535.0);
    *humidity = 100.0 * (float)hum_raw / 65535.0;

    return 0;
}

// Initialize LCD1602 display
int lcd_init() {
    // Initialization sequence (refer to LCD1602 datasheet)
    lcd_send_command(0x30); // Initialization command
    gpioDelay(5);           // Wait 5ms
    lcd_send_command(0x30); // Initialization command
    gpioDelay(1);           // Wait 1ms
    lcd_send_command(0x30); // Initialization command
    gpioDelay(1);           // Wait 1ms
    lcd_send_command(0x20); // 4-bit mode
    gpioDelay(1);           // Wait 1ms
    lcd_send_command(0x28); // 4-bit mode, 2 lines, 5x8 font
    gpioDelay(1);           // Wait 1ms
    lcd_send_command(0x0C); // Display ON, cursor OFF, blink OFF
    gpioDelay(1);           // Wait 1ms
    lcd_send_command(0x06); // Increment cursor, no shift
    gpioDelay(1);           // Wait 1ms

    return 0;
}

// Send a byte to the LCD
void lcd_send_byte(int bits) {
    char data[8];
    for (int i = 0; i < 8; i++) {
        data[i] = (bits >> i) & 0x01;
    }

    char buffer[1] = {data[0]};
    i2cWriteDevice(i2c_handle_lcd, buffer, 1);
    gpioDelay(1); // Short delay

    char buffer2[1] = {data[1]};
    i2cWriteDevice(i2c_handle_lcd, buffer2, 1);
    gpioDelay(1); // Short delay

    char buffer3[1] = {data[2]};
    i2cWriteDevice(i2c_handle_lcd, buffer3, 1);
    gpioDelay(1); // Short delay

    char buffer4[1] = {data[3]};
    i2cWriteDevice(i2c_handle_lcd, buffer4, 1);
    gpioDelay(1); // Short delay

    char buffer5[1] = {data[4]};
    i2cWriteDevice(i2c_handle_lcd, buffer5, 1);
    gpioDelay(1); // Short delay

    char buffer6[1] = {data[5]};
    i2cWriteDevice(i2c_handle_lcd, buffer6, 1);
    gpioDelay(1); // Short delay

    char buffer7[1] = {data[6]};
    i2cWriteDevice(i2c_handle_lcd, buffer7, 1);
    gpioDelay(1); // Short delay

    char buffer8[1] = {data[7]};
    i2cWriteDevice(i2c_handle_lcd, buffer8, 1);
    gpioDelay(1); // Short delay
}

// Send a command to the LCD
void lcd_send_command(unsigned char command) {
    lcd_send_byte(command | 0x00); // Set lower nibble
    lcd_send_byte(command | 0x10); // Set upper nibble
}

// Send data to the LCD
void lcd_send_data(unsigned char data) {
    lcd_send_byte(data | 0x00); // Set lower nibble
    lcd_send_byte(data | 0x10); // Set upper nibble
}

// Clear the LCD display
void lcd_clear() {
    lcd_send_command(0x01); // Clear display command
    gpioDelay(2);           // Wait 2ms
}

// Print text to the LCD
void lcd_print(const char *text) {
    int len = strlen(text);
    for (int i = 0; i < len && i < 16; i++) {
        lcd_send_data(text[i]);
    }
}

// Format data into JSON string
void format_json_data(float temperature, float humidity, char *json_string, size_t json_string_size) {
    time_t rawtime;
    struct tm *timeinfo;
    time(&rawtime);
    timeinfo = localtime(&rawtime);

    json_t *root = json_object();
    json_t *timestamp = json_string(NULL);
    json_t *temperature_json = json_real(temperature);
    json_t *humidity_json = json_real(humidity);

    json_object_set_new(root, "timestamp", timestamp);
    json_object_set_new(root, "temperature", temperature_json);
    json_object_set_new(root, "humidity", humidity_json);

    if (json_dumps(root, 0, json_string) == NULL) {
        fprintf(stderr, "Error encoding JSON\n");
    } else {
        json_decref(root);
        json_decref(timestamp);
        json_decref(temperature_json);
        json_decref(humidity_json);
    }
}

// Log data to JSON file
int log_humidity_data(const char *json_string) {
    FILE *fp = fopen("humidity_log.json", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening humidity_log.json: %s\n", strerror(errno));
        return -1;
    }

    // Check if the file is empty, if so, add the opening bracket
    fseek(fp, 0, SEEK_END);
    long file_size = ftell(fp);
    if (file_size == 0) {
        fprintf(fp, "[");
    } else {
        // Remove the trailing comma and closing bracket if the file already contains data
        char last_char;
        fseek(fp, -1, SEEK_END);
        fread(&last_char, 1, 1, fp);
        if (last_char == ']') {
            fseek(fp, -2, SEEK_END);
            fputc(',', fp);
        }
    }

    fprintf(fp, "%s", json_string);

    // Add a comma after each entry except the last one
    fseek(fp, -1, SEEK_END);
    char last_char;
    fread(&last_char, 1, 1, fp);
    if (last_char == ',') {
        fseek(fp, -1, SEEK_END);
        fputc(']', fp);
    } else {
        fseek(fp, -1, SEEK_END);
        fputc(',', fp);
    }

    fclose(fp);
    return 0;
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize I2C connections
    if (initialize_i2c_sht31() != 0) {
        close_i2c_connections();
        return 1;
    }
    if (initialize_i2c_lcd() != 0) {
        close_i2c_connections();
        return 1;
    }

    // Initialize LCD
    if (lcd_init() != 0) {
        close_i2c_connections();
        return 1;
    }

    float temperature, humidity;
    char json_string[256];

    while (!terminate) {
        // Read sensor data
        if (sht31_read_data(&temperature, &humidity) == 0) {
            // Format data into JSON string
            format_json_data(temperature, humidity, json_string, sizeof(json_string));

            // Display data on LCD
            char temp_str[20];
            char hum_str[20];
            snprintf(temp_str, sizeof(temp_str), "Temp: %.2fC", temperature);
            snprintf(hum_str, sizeof(hum_str), "Hum: %.2f%%", humidity);
            lcd_clear();
            lcd_print(temp_str);
            gpioDelay(1000); // Delay for 1 second
            lcd_clear();
            lcd_print(hum_str);
            gpioDelay(1000); // Delay for 1 second

            // Log data to file
            if (log_humidity_data(json_string) != 0) {
                fprintf(stderr, "Error logging humidity data\n");
            }
        } else {
            fprintf(stderr, "Error reading sensor data\n");
        }

        gpioDelay(2000); // Delay for 2 seconds
    }

    // Clean up
    close_i2c_connections();

    return 0;
}

