        printf("\nExiting gracefully...\n");
    }
}

// Function to initialize GPIO pin
void setupGPIO() {
    if (wiringPiSetupGpio() == -1) { // Use wiringPiSetupGpio for BCM numbering
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        exit(1);
    }

    pinMode(GPIO_PIN, INPUT);
    pullUpDnControl(GPIO_PIN, PUD_UP); // Enable pull-up resistor
}

// Function to initialize UART
void setupUART() {
    int fd = open(UART_PORT, O_RDWR | O_NOCTTY | O_SYNC);
    if (fd == -1) {
        fprintf(stderr, "Error opening UART port: %s\n", strerror(errno));
        exit(1);
    }

    struct termios options;
    tcgetattr(fd, &options);
    cfsetispeed(&options, BAUD_RATE);
    cfsetospeed(&options, BAUD_RATE);
    options.c_cflag |= (CLOCAL | CREAD);
    options.c_cflag &= ~PARENB;
    options.c_cflag &= ~CSTOPB;
    options.c_cflag &= ~CSIZE;
    options.c_cflag |= CS8;
    options.c_lflag &= ~(ICANON | ECHO | ECHOE | ISIG);
    options.c_oflag &= ~OPOST;
    options.c_iflag &= ~(IXON | IXOFF | IXANY);
    tcsetattr(fd, TCSANOW, &options);

    close(fd); // Close the file descriptor after configuration
}

// Function to log an event with timestamp
void logEvent(const char *eventString) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    strftime(logBuffer[bufferIndex].event, sizeof(logBuffer[bufferIndex].event), "%Y-%m-%d %H:%M:%S", t);
    strcpy(logBuffer[bufferIndex].timestamp, "Timestamp not available in UART mode");

    // Get timestamp as string
    char timestampStr[30];
    strftime(timestampStr, sizeof(timestampStr), "%Y-%m-%d %H:%M:%S", localtime(&now));

    // Print to UART
    printf("UART: %s, %s\n", timestampStr, eventString);
}

// Function to print the last 10 events from the circular buffer
void printBufferToUART() {
    int startIndex = (bufferIndex + (BUFFER_SIZE - 10)) % BUFFER_SIZE; // Calculate the start index

    printf("\n--- Interlock Log ---\n");
    for (int i = 0; i < 10; i++) {
        int currentIndex = (startIndex + i) % BUFFER_SIZE;
        printf("%s, %s\n", logBuffer[currentIndex].timestamp, logBuffer[currentIndex].event);
    }
    printf("--- End of Log ---\n\n");
}

