        if (switchState == LOW) {
            logEvent("Interlock triggered!");
        } else {
            logEvent("Interlock released.");
        }

        // Increment the buffer index, wrapping around if necessary
        bufferIndex = (bufferIndex + 1) % BUFFER_SIZE;

        delay(50); // Delay to prevent excessive CPU usage
    }

    // Print the buffer before exiting
    printBufferToUART();

    return 0;
