```c
#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <string.h>
#include <pigpio.h>

#define BUTTON_PIN 4
#define LOCK1_PIN 17
#define LOCK2_PIN 27
#define DEBOUNCE_TIME 50  // microseconds

int lock_event_log(const char *event, int lock_id) {
    FILE *log_file = fopen("lock_events.log", "a");
    if (!log_file) {
        perror("Failed to open log file");
        return -1;
    }

    time_t now;
    struct tm *timeinfo;
    char timestamp[30];

    time(&now);
    timeinfo = localtime(&now);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(log_file, "%s Lock %d %s\n", timestamp, lock_id, event);
    fclose(log_file);
    return 0;
}

void handle_lock(int pin, int lock_id) {
    gpioWrite(LOCK1_PIN, 1);  // Turn off both locks to ensure safety
    gpioWrite(LOCK2_PIN, 1);

    if (pin == LOCK1_PIN) {
        gpioWrite(LOCK1_PIN, 0);
        lock_event_log("Locked", lock_id);
    } else if (pin == LOCK2_PIN) {
        gpioWrite(LOCK2_PIN, 0);
        lock_event_log("Locked", lock_id);
    }
}

int main() {
    int button_state, last_button_state;
    int lock1_state, lock2_state;

    if (gpioInitialise() < 0) {
        perror("GPIO initialization failed");
        return 1;
    }

    gpioSetMode(BUTTON_PIN, PI_INPUT);
    gpioSetMode(LOCK1_PIN, PI_OUTPUT);
    gpioSetMode(LOCK2_PIN, PI_OUTPUT);

    gpioPullUpDnControl(BUTTON_PIN, PI_PUD_UP);
    gpioSetAlertFunc(BUTTON_PIN, buttonPressed);

    last_button_state = 1;
    while (1) {
        button_state = gpioRead(BUTTON_PIN);
        if ((button_state != last_button_state) && (button_state == 0)) {
            gpioDelay(DEBOUNCE_TIME);
            button_state = gpioRead(BUTTON_PIN);
            if (button_state == 0) {
                lock1_state = gpioRead(LOCK1_PIN);
                lock2_state = gpioRead(LOCK2_PIN);

                if (lock1_state == 1) {
                    handle_lock(LOCK1_PIN, 1);
                } else if (lock2_state == 1) {
                    handle_lock(LOCK2_PIN, 2);
                }
            }
        }
        last_button_state = button_state;
    }

    gpioTerminate();
    return 0;
}
```

### Explanation:

1. **GPIO Initialization**: The program initializes the GPIO pins and sets up the button as an input with pull-up resistor.
2. **Debouncing**: The button state is checked only after a debounce delay to ensure reliable readings.
3. **Lock Control**: When the button is pressed and debounced, the corresponding lock is activated, and the event is logged.
4. **Logging**: Events are logged to `lock_events.log` with a timestamp, lock ID, and action performed.
5. **Safety Measures**: Both locks are turned off at the start of each lock command to prevent accidental double locking.

### Compilation and Running:
- Compile the program using `gcc`:
  ```sh
  gcc -o door_lock_controller door_lock_controller.c -lpigpio
  ```
- Run the compiled program:
  ```sh
  ./door_lock_controller
  ```

This setup ensures safe and reliable operation of the door locks while maintaining a record of all actions taken.

