// Configuration structure
typedef struct {
    int gpio_door_lock_1;
    int gpio_door_lock_2;
    int gpio_button;
    char *log_file_path;
    char *mq_name;
    int mq_flags;
    unsigned int mq_maxmsglen;
    unsigned int mq_msgtlen;
    int mq_prio;
    unsigned int mq_curmsgs;
} Config;

// Global configuration
Config config;

// Function prototypes
int read_config(const char *filename, Config *config);
void initialize_gpio(Config config);
void cleanup_gpio();
void log_event(int lock_id, const char *action);
void send_message_to_queue(int lock_id, const char *action);
void button_callback(int gpio, int level, uint32_t tick);
void signal_handler(int signum);
char* get_timestamp();

// Mutex for thread safety
pthread_mutex_t log_mutex = PTHREAD_MUTEX_INITIALIZER;

// Message queue variables
mqd_t mq;
struct timespec ts;

// Function to read configuration from file
int read_config(const char *filename, Config *config) {
    FILE *fp = fopen(filename, "r");
    if (fp == NULL) {
        perror("Error opening config file");
        return -1;
    }

    char line[256];
    while (fgets(line, sizeof(line), fp)) {
        // Remove leading/trailing whitespace
        char *start = line;
        while (isspace((unsigned char)*start)) start++;
        if (*start == '#' || *start == '\0') continue; // Skip comments and empty lines

        char *key = strtok(start, "=");
        char *value = strtok(NULL, "=");

        if (key != NULL && value != NULL) {
            if (strcmp(key, "gpio_door_lock_1") == 0) {
                config->gpio_door_lock_1 = atoi(value);
            } else if (strcmp(key, "gpio_door_lock_2") == 0) {
                config->gpio_door_lock_2 = atoi(value);
            } else if (strcmp(key, "gpio_button") == 0) {
                config->gpio_button = atoi(value);
            } else if (strcmp(key, "log_file_path") == 0) {
                strncpy(config->log_file_path, value, sizeof(config->log_file_path) - 1);
                config->log_file_path[sizeof(config->log_file_path) - 1] = '\0'; // Ensure null termination
            } else if (strcmp(key, "mq_name") == 0) {
                strncpy(config->mq_name, value, sizeof(config->mq_name) - 1);
                config->mq_name[sizeof(config->mq_name) - 1] = '\0'; // Ensure null termination
            } else if (strcmp(key, "mq_flags") == 0) {
                config->mq_flags = atoi(value);
            } else if (strcmp(key, "mq_maxmsglen") == 0) {
                config->mq_maxmsglen = atoi(value);
            } else if (strcmp(key, "mq_msgtlen") == 0) {
                config->mq_msgtlen = atoi(value);
            } else if (strcmp(key, "mq_prio") == 0) {
                config->mq_prio = atoi(value);
            } else if (strcmp(key, "mq_curmsgs") == 0) {
                config->mq_curmsgs = atoi(value);
            }
        }
    }

    fclose(fp);
    return 0;
}

// Function to initialize GPIO pins
void initialize_gpio(Config config) {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        exit(1);
    }

    gpioSetMode(config.gpio_door_lock_1, PI_OUTPUT);
    gpioSetMode(config.gpio_door_lock_2, PI_OUTPUT);
    gpioSetMode(config.gpio_button, PI_INPUT);
    gpioSetPullUpDown(config.gpio_button, PI_PUD_UP);

    // Set up interrupt on the button
    gpioSetAlertFuncEx(config.gpio_button, button_callback, NULL);
}

// Function to cleanup GPIO pins
void cleanup_gpio() {
    gpioTerminate();
}

// Function to log an event to a file
void log_event(int lock_id, const char *action) {
    pthread_mutex_lock(&log_mutex);
    FILE *fp = fopen(config.log_file_path, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        pthread_mutex_unlock(&log_mutex);
        return;
    }

    char *ts_str = get_timestamp();
    fprintf(fp, "%s Lock %d %s\n", ts_str, lock_id, action);
    free(ts_str); // Free the timestamp string after use

    fclose(fp);
    pthread_mutex_unlock(&log_mutex);
}

// Function to send a message to the message queue
void send_message_to_queue(int lock_id, const char *action) {
    char message[128];
    snprintf(message, sizeof(message), "%d,%s", lock_id, action);

    if (mq_send(mq, message, strlen(message), 0) == -1) {
        perror("mq_send failed");
    }
}

// Button callback function
void button_callback(int gpio, int level, uint32_t tick) {
    static uint32_t last_tick = 0;
    static int state = 0; // 0: idle, 1: pressed, 2: released

    uint32_t current_tick = gpioTick();

    if (level == 0) { // Button is pressed
        if (current_tick - last_tick > 500000) { // Debounce delay of 500ms
            if (state == 0) {
                state = 1;
                gpioWrite(config.gpio_door_lock_1, 1); // Lock 1
                gpioWrite(config.gpio_door_lock_2, 1); // Lock 2
                log_event(1, "Locked");
                log_event(2, "Locked");
                send_message_to_queue(1, "Locked");
                send_message_to_queue(2, "Locked");

                // Wait for a short time before unlocking
                sleep(5);
                gpioWrite(config.gpio_door_lock_1, 0); // Unlock 1
                gpioWrite(config.gpio_door_lock_2, 0); // Unlock 2
                log_event(1, "Unlocked");
                log_event(2, "Unlocked");
                send_message_to_queue(1, "Unlocked");
                send_message_to_queue(2, "Unlocked");

                state = 2;
            }
        }
    } else if (level == 1) { // Button is released
        if (state == 1) {
            state = 0;
        }
    }

    last_tick = current_tick;
}

// Signal handler function
void signal_handler(int signum) {
    if (signum == SIGINT || signum == SIGTERM) {
        printf("Received signal %d, cleaning up...\n", signum);
        cleanup_gpio();
        if (mq != (mqd_t)-1) {
            mq_close(mq);
            mq_unlink(config.mq_name);
        }
        pthread_mutex_destroy(&log_mutex);
        exit(0);
    }
}

// Function to get a timestamp string
char* get_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    char *timestamp = (char*)malloc(21 * sizeof(char)); // YYYY-MM-DD HH:MM:SS\0

    if (timestamp == NULL) {
        perror("Failed to allocate memory for timestamp");
        return NULL;
    }

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, 21, "%Y-%m-%d %H:%M:%S", timeinfo);
    return timestamp;
}

int main() {
    // Initialize configuration
    strncpy(config.log_file_path, "lock_events.log", sizeof(config.log_file_path) - 1);
    config.log_file_path[sizeof(config.log_file_path) - 1] = '\0';
    strncpy(config.mq_name, "/door_lock_control", sizeof(config.mq_name) - 1);
    config.mq_name[sizeof(config.mq_name) - 1] = '\0';
    config.mq_flags = 0;
    config.mq_maxmsglen = 128;
    config.mq_msgtlen = 16;
    config.mq_prio = 0;
    config.mq_curmsgs = 0;

    // Read configuration from file
    if (read_config("config.txt", &config) != 0) {
        fprintf(stderr, "Failed to read configuration file, exiting\n");
        return 1;
    }

    // Initialize GPIO
    initialize_gpio(config);

    // Set up signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Open message queue
    mq = mq_open(config.mq_name, config.mq_flags | O_CREAT | O_NONBLOCK, 0666, NULL);
    if (mq == (mqd_t)-1) {
        perror("mq_open failed");
        cleanup_gpio();
        return 1;
    }

    // Main loop
    while (1) {
        sleep(1); // Reduce CPU usage
    }

    return 0;
}

