#include <wiringPi.h>
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

// Define the GPIO pin numbers for the shift register
#define DATA_PIN 0
#define SH_CP_PIN 1
#define ST_CP_PIN 2
#define OE_PIN 3

// Define the segment values for each digit (0-9)
int segments[10] = {
    0b00111111, // 0
    0b00000110, // 1
    0b01011011, // 2
    0b01001111, // 3
    0b01100110, // 4
    0b01101101, // 5
    0b01111101, // 6
    0b00000111, // 7
    0b01111111, // 8
    0b01101111  // 9
};

void shiftOut(int dataPin, int clockPin, int val) {
    for (int i = 7; i >= 0; i--) {
        digitalWrite(dataPin, val & (1 << i) ? HIGH : LOW);
        digitalWrite(clockPin, HIGH);
        digitalWrite(clockPin, LOW);
    }
}

int main() {
    // Initialize WiringPi
    if (wiringPiSetup() == -1) {
        printf("wiringPi setup error\n");
        return 1;
    }

    // Set up the GPIO pins as outputs
    pinMode(DATA_PIN, OUTPUT);
    pinMode(SH_CP_PIN, OUTPUT);
    pinMode(ST_CP_PIN, OUTPUT);
    pinMode(OE_PIN, OUTPUT);

    // Turn off output enable (OE)
    digitalWrite(OE_PIN, LOW);

    while (1) {
        // Generate a random number between 0 and 9
        int randomNumber = rand() % 10;

        // Send the segment value to the shift register
        shiftOut(DATA_PIN, SH_CP_PIN, segments[randomNumber]);

        // Pulse the storage clock to latch the data
        digitalWrite(ST_CP_PIN, HIGH);
        digitalWrite(ST_CP_PIN, LOW);

        // Wait for 2 seconds before displaying the next number
        sleep(2);
    }

    return 0;
}
