   ```

### Step 2: Write the C Program

Here's a complete C program that reads analog data from the MCP3008 ADC every second and logs it to a CSV file:

```c
#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <string.h>

#define SPI_CHANNEL 0

// Function to read ADC value
int read_adc(int channel) {
    int val;

    // Construct command
    unsigned char cmd[3] = {0x01, (channel << 4) | 0x08, 0x00};

    // Send command to ADC
    wiringPiSPIDataRW(SPI_CHANNEL, cmd, 3);

    // Read back data
    val = (cmd[1] << 8) | cmd[2];

    return val;
}

int main() {
    FILE *file;
    char filename[] = "adc_data.csv";
    time_t t;

    // Initialize WiringPi
    if(wiringPiSetup() == -1) {
        printf("wiringPi setup failed!\n");
        exit(1);
    }

    // Open SPI channel
    if (wiringPiSPISetup(SPI_CHANNEL, 1000000) == -1) {
        printf("Failed to open SPI device\n");
        return 1;
    }

    // Open CSV file for logging
    file = fopen(filename, "a");
    if (!file) {
        perror("Error opening file");
        return 1;
    }

    // Log header
    fprintf(file, "Timestamp,ADC_Value\n");

    while (1) {
        // Read ADC value from channel 0
        int adc_value = read_adc(0);

        // Get current timestamp
        t = time(NULL);

        // Format and write to CSV
        fprintf(file, "%s,%d\n", ctime(&t), adc_value);

        // Sleep for 1 second
        sleep(1);
    }

    fclose(file);
    return 0;
}
