    pthread_mutex_lock(&mqtt_mutex);

    char *timestamp = iso8601_timestamp();
    json_t *root = json_object();
    json_object_set_new(root, "timestamp", json_string(timestamp));
    json_object_set_new(root, "sensor_id", json_string("PIR_Sensor_1"));
    json_object_set_new(root, "event_type", json_string(event_type));

    char *payload = json_dumps(root, JSON_COMPACT);
    json_decref(root);

    int rc = mosquitto_publish(mosq, NULL, config.mqtt_topic, strlen(payload), payload, 0, false);
    if (rc != MOSQ_ERR_SUCCESS) {
        syslog(LOG_ERR, "Error publishing message: %s", mosquitto_strerror(rc));
    } else {
        syslog(LOG_INFO, "Published message: %s", payload);
    }

    free(timestamp);
    free(payload);

    pthread_mutex_unlock(&mqtt_mutex);
}

// Function to generate ISO 8601 timestamp
char* iso8601_timestamp() {
    time_t now = time(NULL);
    struct tm *tmp = localtime(&now);
    if (tmp == NULL) {
        syslog(LOG_ERR, "localtime error");
        return NULL;
    }
    char *buf = malloc(sizeof(char) * 32);
    if (buf == NULL) {
        syslog(LOG_ERR, "malloc error");
        return NULL;
    }
    strftime(buf, 32, "%Y-%m-%dT%H:%M:%SZ", tmp);
    return buf;
}

// Signal handler for graceful shutdown
void signal_handler(int signum) {
    syslog(LOG_INFO, "Signal received: %d. Shutting down...", signum);
    running = 0;

    gpioSetAlertFuncEx(config.pir_gpio, NULL, NULL); // Disable interrupt
    gpioWrite(config.buzzer_gpio, 0); // Deactivate buzzer

    pthread_mutex_lock(&mqtt_mutex);
    mosquitto_disconnect(mosq);
    pthread_mutex_unlock(&mqtt_mutex);

    pthread_join(mqtt_thread, NULL);

    mosquitto_destroy(mosq);
    mosquitto_lib_cleanup();
    gpioTerminate();

    syslog(LOG_INFO, "Shutdown complete.");
    closelog();
    exit(0);
}

// MQTT thread function
void *mqtt_thread_func(void *arg) {
    (void)arg;
    mqtt_connect_and_loop(config.mqtt_broker_address, config.mqtt_broker_port);
    return NULL;
}

int main() {
    openlog("motion_buzzer", LOG_PID, LOG_USER);
    syslog(LOG_INFO, "Starting motion buzzer application...");

    // Load configuration from file
    if (load_config("config.json", &config) != 0) {
        syslog(LOG_ERR, "Failed to load configuration. Exiting.");
        closelog();
        return 1;
    }

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        syslog(LOG_ERR, "pigpio initialisation failed");
        closelog();
        return 1;
    }

    // Configure GPIO pins
    if (gpioSetMode(config.pir_gpio, PI_INPUT) != 0) {
        syslog(LOG_ERR, "Failed to set PIR GPIO mode");
        gpioTerminate();
        closelog();
        return 1;
    }

    if (gpioSetPullUpDown(config.pir_gpio, PI_PUD_DOWN) != 0) {
         syslog(LOG_WARNING, "Failed to set PIR GPIO pull-down. Continuing anyway.");
    }

    if (gpioSetMode(config.buzzer_gpio, PI_OUTPUT) != 0) {
        syslog(LOG_ERR, "Failed to set buzzer GPIO mode");
        gpioTerminate();
        closelog();
        return 1;
    }

    // Initialize MQTT
    mosquitto_lib_init();
    mosq = mosquitto_new(NULL, true, NULL);
    if (!mosq) {
        syslog(LOG_ERR, "Failed to create mosquitto instance.");
        gpioTerminate();
        closelog();
        return 1;
    }

    // Create MQTT thread
    if (pthread_create(&mqtt_thread, NULL, mqtt_thread_func, NULL) != 0) {
        syslog(LOG_ERR, "Failed to create MQTT thread.");
        mosquitto_destroy(mosq);
        mosquitto_lib_cleanup();
        gpioTerminate();
        closelog();
        return 1;
    }

    // Set up signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Set up motion detection interrupt
    gpioSetAlertFuncEx(config.pir_gpio, motion_callback, NULL);

    // Keep the program running until a signal is received
    while (running) {
        sleep(1);
    }

    return 0;
}

