    gpioSetMode(PIR_PIN, PI_INPUT);
    gpioSetMode(RELAY_PIN, PI_OUTPUT);

    // Activate pull-up resistor on PIR_PIN
    gpioSetPullUpDown(PIR_PIN, PI_PUD_UP);

    // Continuously check for motion
    while (1) {
        int level = gpioRead(PIR_PIN);
        if (level == 1) { // Motion detected
            log_event("Motion detected");

            // Turn on the relay
            gpioWrite(RELAY_PIN, 1);

            // Wait for 5 seconds
            sleep(DELAY_TIME);

            // Turn off the relay
            gpioWrite(RELAY_PIN, 0);
        }
        // Small delay to avoid busy-waiting
        sleep(1);
    }

    // Cleanup GPIO
    gpioTerminate();

    return EXIT_SUCCESS;
}

