First, ensure you have the `wiringPi` library installed. You can install it using the following command:

```bash
sudo apt-get update
sudo apt-get install wiringpi
```

Next, write the C program as follows:

```c
#include <stdio.h>
#include <wiringPi.h>
#include <stdlib.h>
#include <unistd.h>

#define PIR_PIN 17   // GPIO pin for PIR sensor (GPIO17)
#define BUZZER_PIN 18 // GPIO pin for buzzer (GPIO18)

// Function prototypes
void setupGPIO();
void cleanupGPIO();

int main() {
    int pirPin = PIR_PIN;
    int buzzerPin = BUZZER_PIN;

    // Initialize wiringPi
    if(wiringPiSetup() == -1) {
        printf("wiringPiSetup failed!\n");
        return 1;
    }

    // Set up GPIO pins
    setupGPIO(pirPin, buzzerPin);

    // Main loop
    while(1) {
        // Read the state of the PIR sensor
        if(digitalRead(pirPin)) { // Check if motion is detected
            printf("Motion detected!\n");
            // Trigger the buzzer for 2 seconds
            digitalWrite(buzzerPin, HIGH);
            usleep(2000000); // Wait for 2 seconds
            digitalWrite(buzzerPin, LOW);
        }
        sleep(1); // Sleep for 1 second to avoid high CPU usage
    }

    // Cleanup GPIO
    cleanupGPIO();

    return 0;
}

