#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <errno.h>
#include <pigpio.h>

// Define GPIO pins
#define PIR_SENSOR_1 17
#define PIR_SENSOR_2 22
#define BUZZER_1 18
#define BUZZER_2 23

// Debounce time in milliseconds
#define DEBOUNCE_TIME 200

// Global variables
FILE *log_file = NULL;
volatile sig_atomic_t terminate = 0;

// Function prototypes
void initialize_gpio();
void cleanup_gpio();
void log_motion(int gpio_pin);
void play_buzzer(int gpio_pin, int duration_ms);
void pir_callback_1(void *userdata);
void pir_callback_2(void *userdata);

// Signal handler for graceful shutdown
void signal_handler(int signal)
{
    printf("Caught signal %d, terminating...\n", signal);
    terminate = 1;
}

int main()
{
    // Initialize pigpio
    if (gpioInitialise() < 0)
    {
        fprintf(stderr, "pigpio initialisation failed: %s\n", strerror(errno));
        return 1;
    }

    // Register signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Initialize GPIO pins
    initialize_gpio();

    // Open log file
    log_file = fopen("motion.log", "a");
    if (log_file == NULL)
    {
        fprintf(stderr, "Failed to open log file: %s\n", strerror(errno));
        cleanup_gpio();
        gpioTerminate();
        return 1;
    }

    // Set up interrupt routines for PIR sensors
    if (gpioSetISRFuncEx(PIR_SENSOR_1, RISING_EDGE, 0, pir_callback_1, NULL) != 0)
    {
        fprintf(log_file, "%s - Failed to set ISR for PIR_SENSOR_1\n", __TIME__);
        fclose(log_file);
        cleanup_gpio();
        gpioTerminate();
        return 1;
    }
    if (gpioSetISRFuncEx(PIR_SENSOR_2, RISING_EDGE, 0, pir_callback_2, NULL) != 0)
    {
        fprintf(log_file, "%s - Failed to set ISR for PIR_SENSOR_2\n", __TIME__);
        fclose(log_file);
        cleanup_gpio();
        gpioTerminate();
        return 1;
    }

    printf("Motion detection system started. Press Ctrl+C to exit.\n");

    // Main loop (wait for termination signal)
    while (!terminate)
    {
        // Do other tasks here if needed
        gpioDelay(100); // Sleep for 100ms to avoid busy-waiting
    }

    // Cleanup resources before exiting
    printf("Cleaning up resources...\n");
    fclose(log_file);
    cleanup_gpio();
    gpioTerminate();

    printf("Exiting.\n");
    return 0;
}

void initialize_gpio()
{
    // Set PIR sensor pins as inputs
    gpioSetMode(PIR_SENSOR_1, PI_INPUT);
    gpioSetMode(PIR_SENSOR_2, PI_INPUT);

    // Set buzzer pins as outputs
    gpioSetMode(BUZZER_1, PI_OUTPUT);
    gpioSetMode(BUZZER_2, PI_OUTPUT);

    // Initialize buzzer state to LOW
    gpioWrite(BUZZER_1, 0);
    gpioWrite(BUZZER_2, 0);
}

void cleanup_gpio()
{
    // Disable interrupts on PIR sensor pins
    gpioSetISRFuncEx(PIR_SENSOR_1, RISING_EDGE, 0, NULL, NULL);
    gpioSetISRFuncEx(PIR_SENSOR_2, RISING_EDGE, 0, NULL, NULL);

    // Reset buzzer pins to LOW
    gpioWrite(BUZZER_1, 0);
    gpioWrite(BUZZER_2, 0);
}

void log_motion(int gpio_pin)
{
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[32];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%dT%H:%M:%SZ", t);

    fprintf(log_file, "%s - Motion detected on GPIO %d\n", timestamp, gpio_pin);
    fflush(log_file); // Ensure data is written immediately
}

void play_buzzer(int gpio_pin, int duration_ms)
{
    gpioWrite(gpio_pin, 1); // Turn buzzer ON
    gpioDelay(duration_ms);
    gpioWrite(gpio_pin, 0); // Turn buzzer OFF
}

void pir_callback_1(void *userdata)
{
    static unsigned long last_interrupt_time = 0;
    unsigned long current_time = gpioTick();

    // Debouncing: Check if enough time has passed since the last interrupt
    if (current_time - last_interrupt_time > DEBOUNCE_TIME * 1000) // Convert ms to microseconds
    {
        log_motion(PIR_SENSOR_1);
        play_buzzer(BUZZER_1, 500); // Play buzzer for 500ms
        last_interrupt_time = current_time;
    }
}

void pir_callback_2(void *userdata)
{
    static unsigned long last_interrupt_time = 0;
    unsigned long current_time = gpioTick();

    // Debouncing: Check if enough time has passed since the last interrupt
    if (current_time - last_interrupt_time > DEBOUNCE_TIME * 1000) // Convert ms to microseconds
    {
        log_motion(PIR_SENSOR_2);
        play_buzzer(BUZZER_2, 500); // Play buzzer for 500ms
        last_interrupt_time = current_time;
    }
}

